INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-24', E'파수군으로의 부르심 (에스겔 3장)', E'에스겔 3장', E'하나님께서는 에스겔에게 특별한 사명을 주시며 그를 이스라엘 족속의 파수꾼으로 세우십니다. 먼저 하나님은 에스겔에게 두루마리를 먹으라고 명하시는데, 이는 하나님의 말씀을 온전히 받아들이고 내면화하라는 상징적 행위였습니다. 놀랍게도 심판의 메시지가 가득한 그 두루마리가 에스겔의 입에서는 꿀같이 달았다고 기록됩니다. 이것은 하나님의 말씀 자체가 선지자에게는 기쁨이요 생명이 됨을 보여줍니다.\n\n그러나 하나님은 에스겔이 전할 메시지가 쉽게 받아들여지지 않을 것임을 미리 알려주십니다. "이스라엘 족속은 이마가 굳고 마음이 굳어 네 말을 듣고자 아니하리니"(겔 3:7)라고 말씀하시며, 오히려 언어가 다른 이방 민족들이었다면 그들의 말을 들었을 것이라고 하십니다. 이스라엘의 문제는 무지가 아니라 의도적인 거부였던 것입니다. 이에 하나님은 에스겔의 이마를 금강석처럼 굳게 하셔서 반역하는 백성들 앞에서도 흔들리지 않도록 준비시키십니다.\n\n특별히 주목할 것은 파수꾼의 책임에 대한 엄중한 경고입니다. 하나님은 에스겔에게 악인이든 의인이든 그들을 깨우쳐야 할 책임을 부여하시며, 만약 경고하지 않으면 그들의 피 값을 에스겔에게서 찾겠다고 말씀하십니다. 이것은 단순히 메시지를 전달하는 것이 아니라, 영혼에 대한 거룩한 책임을 지는 것임을 보여줍니다. 파수꾼은 사람들이 듣든지 듣지 않든지 하나님의 말씀을 신실하게 전해야 합니다.\n\n하나님의 영이 에스겔을 들어 올리시고 권능으로 감동시키실 때, 그는 근심하고 분한 마음으로 갔다고 기록합니다. 이는 거부당할 것을 알면서도 가야 하는 선지자의 아픔을 보여줍니다. 그럼에도 불구하고 에스겔은 순종하여 포로로 잡혀간 동족들에게로 갑니다. 칠 일 동안 두려워 떨며 그들 중에 머물던 에스겔에게 하나님은 다시 말씀하시며, 그를 이스라엘의 파수꾼으로 공식적으로 세우십니다. 비록 그들이 듣지 않고 반역할지라도, 하나님의 사랑은 끝까지 경고의 나팔을 불게 하시는 것입니다.', E'오늘의 핵심\n하나님께서는 에스겔을 이스라엘의 파수꾼으로 세우시며, 백성들이 거부할 것을 아시면서도 끝까지 말씀을 전하게 하심으로 그분의 변함없는 사랑을 보여주십니다.\n\n묵상 질문\n1. 하나님의 말씀이 때로는 쓰지만 결국 꿀같이 단 이유는 무엇일까요?\n2. 내게 맡겨진 영혼들을 위해 파수꾼의 책임을 다하고 있나요?\n3. 거부와 반대를 두려워하여 전해야 할 진리를 침묵하고 있지는 않나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-25', E'남유다에 대한 징계와 심판 (에스겔 4장)', E'에스겔 4장', E'하나님께서는 에스겔에게 특별한 상징 행동들을 명하셨습니다. 토판에 예루살렘을 그리고 포위 공격하는 모형을 만들어 이스라엘 족속에게 징조가 되게 하신 것입니다. 이 행동극은 곧 닥칠 예루살렘의 운명을 미리 보여주는 예언적 표징이었습니다. \n\n더욱 놀라운 것은 에스겔이 왼쪽으로 390일, 오른쪽으로 40일을 누워서 이스라엘과 유다의 죄악을 대신 담당하는 상징 행동입니다. 하루가 일 년을 대표하는 이 날수는 북이스라엘과 남유다가 범죄한 기간을 나타냅니다. 에스겔은 줄에 묶여 몸을 돌리지도 못한 채 이 고통스러운 예언을 수행해야 했습니다.\n\n하나님께서는 에스겔에게 하루 이십 세겔(약 230g)의 음식과 육분의 일 힌(약 0.6리터)의 물만으로 연명하게 하셨습니다. 이는 포위된 예루살렘 성 안에서 백성들이 겪을 극심한 기근을 미리 체험하는 것이었습니다. 특히 인분으로 음식을 구워 먹으라는 명령은 이방 땅에서 부정한 음식을 먹게 될 포로 생활의 비참함을 예고했습니다. \n\n에스겔이 자신은 부정한 것을 먹은 적이 없다고 호소하자, 하나님께서는 인분 대신 쇠똥을 사용하도록 허락하셨습니다. 이는 하나님의 자비로우신 배려였지만, 동시에 예루살렘이 겪을 심판의 참혹함은 변하지 않았습니다. "떡과 물이 부족하여 피차에 두려워 하여 떨며 그 죄악 중에서 쇠패하리라"(겔 4:17)는 하나님의 선언은 반복된 불순종의 결과가 얼마나 비참한지를 보여줍니다.\n\n에스겔의 상징적 행동은 단순한 연극이 아니라 자신의 몸으로 백성의 고통을 대신 체험하는 중보적 사역이었습니다. 선지자는 하나님의 심판 메시지를 전하면서도 백성과 함께 아파하는 목자의 심정을 품고 있었던 것입니다.', E'오늘의 핵심\n하나님께서는 에스겔의 몸을 통해 예루살렘이 당할 포위와 기근, 그리고 포로 생활의 고통을 미리 보여주시며, 계속된 불순종이 가져올 심판의 참혹함을 경고하셨습니다.\n\n묵상 질문\n1. 에스겔처럼 다른 사람의 아픔을 내 몸으로 느끼며 중보한 경험이 있나요?\n2. 하나님의 경고를 듣고도 무시했다가 어려움을 겪은 적이 있으신가요?\n3. 오늘 내 삶에서 하나님께서 반복해서 말씀하시는 경고는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-26', E'남유다에 대한 징계와 심판 (에스겔 5장)', E'에스겔 5장', E'에스겔 선지자에게 하나님께서는 매우 충격적인 상징 행동을 명하십니다. 날카로운 칼로 머리털과 수염을 깎아 저울에 달아 삼등분하라는 것입니다. 고대 근동에서 머리털과 수염은 인간의 존엄과 명예를 상징했기에, 이를 깎는다는 것은 극도의 수치와 모욕을 의미했습니다. 더욱이 제사장 가문 출신인 에스겔에게 이는 율법이 금하는 행위였습니다. 하나님께서는 이처럼 파격적인 방법을 통해 예루살렘에 임할 심판의 참혹함을 미리 보여주고 계십니다.\n\n삼등분한 머리털의 운명은 예루살렘 백성들이 맞이할 비극적 결말을 예표합니다. 삼분의 일은 성읍 안에서 불에 타 죽고, 삼분의 일은 칼에 죽임을 당하며, 나머지 삼분의 일은 사방에 흩어져 유랑하게 됩니다. 하나님께서는 예루살렘을 열방의 중심에 두어 빛과 소금의 역할을 감당하게 하셨으나, 그들은 오히려 주변 이방 민족들보다 더 악하게 행동했습니다. 하나님의 성소를 온갖 우상과 가증한 것들로 더럽히고, 율법을 버리며, 정의와 공의를 짓밟았습니다.\n\n특별히 주목할 것은 하나님께서 "내가 나의 삶을 두고 맹세하노니"라고 말씀하시는 대목입니다. 이는 하나님께서 당신의 존재 자체를 걸고 하시는 가장 엄중한 선언입니다. 예루살렘의 죄악이 얼마나 극에 달했는지, 하나님의 진노가 얼마나 깊은지를 보여줍니다. 그럼에도 불구하고 에스겔은 옷자락에 머리털 얼마를 싸두라는 명령을 받습니다. 완전한 멸망 가운데서도 하나님께서는 작은 남은 자들을 보존하시는 은혜의 흔적을 남기십니다. 이는 심판 중에도 구원의 소망을 완전히 거두지 않으시는 하나님의 신실하심을 보여주는 것입니다.', E'오늘의 핵심\n하나님께서는 에스겔의 충격적인 상징 행동을 통해 예루살렘의 완전한 파멸을 예고하시면서도, 옷자락에 싸둔 머리털처럼 소수의 남은 자를 통한 회복의 가능성을 열어두십니다.\n\n묵상 질문\n1. 하나님의 성소를 더럽힌 예루살렘처럼, 나는 어떤 모습으로 하나님의 거룩함을 훼손하고 있진 않나요?\n2. 극심한 심판 중에도 남은 자를 보존하시는 하나님의 은혜가 내 삶에서는 어떻게 나타나고 있나요?\n3. 하나님께서 나에게 맡기신 사명을 이방인들보다 못하게 수행하고 있는 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-27', E'남유다에 대한 징계와 심판 (에스겔 6장)', E'에스겔 6장', E'여호와의 말씀이 에스겔에게 임하여 이스라엘 산들을 향한 심판의 메시지를 전하게 하십니다. 하나님께서는 산과 언덕, 시내와 골짜기에 이르기까지 온 땅에 칼이 임하게 하여 산당을 멸하실 것이라고 선포하십니다. 이스라엘 백성이 그토록 의지하며 섬기던 우상들과 제단들이 모두 황폐하게 되고, 우상 앞에 그들의 시체가 엎드러지게 될 것이라는 충격적인 심판의 내용이 전해집니다.\n\n하나님의 심판이 이토록 철저한 이유는 이스라엘이 "음란한 마음으로 나를 떠나고 음란한 눈으로 우상을 섬겨"(겔 6:9) 하나님을 근심하게 했기 때문입니다. 그들은 높은 산 꼭대기와 푸른 나무 아래, 무성한 상수리나무 아래 곳곳에 우상을 위한 제단을 쌓고 분향했습니다. 하나님과의 언약을 저버리고 가나안의 우상 숭배에 빠져든 그들의 영적 간음이 얼마나 깊었는지를 보여주는 대목입니다.\n\n그러나 하나님의 심판 가운데서도 은혜의 빛줄기가 비칩니다. 칼을 피하여 이방인들 중에 살아남은 자들이 있게 하시겠다는 약속입니다. 이들은 포로로 끌려가 이방 땅에서 비로소 자신들의 죄를 깨닫고 스스로 한탄하게 될 것입니다. 고난의 시간이 오히려 회개와 깨달음의 기회가 되는 것입니다. 그때서야 그들은 여호와가 참 하나님이심을 알게 되고, 하나님의 경고가 헛된 말이 아니었음을 깨닫게 됩니다.\n\n에스겔은 손뼉을 치고 발을 구르는 상징적 행동으로 이스라엘의 비극적 운명을 애통해합니다. 칼과 기근과 전염병이라는 삼중고가 거리에 따라 차별 없이 모든 이에게 임할 것입니다. 이는 단순한 재앙이 아니라 하나님의 거룩하심을 모독한 것에 대한 필연적 결과였습니다. 우상 숭배의 현장이었던 그곳들이 이제는 심판의 현장이 되어, 하나님의 공의가 얼마나 철저한지를 온 땅에 증거하게 됩니다.', E'오늘의 핵심\n하나님께서는 이스라엘의 우상 숭배에 대해 철저한 심판을 선포하시면서도, 포로 중에 남은 자들을 통해 회개와 회복의 가능성을 열어두십니다.\n\n묵상 질문\n1. 오늘날 우리가 하나님보다 더 의지하고 있는 현대의 ''우상''은 무엇일까요?\n2. 고난의 시간이 오히려 하나님을 깊이 만나는 은혜의 통로가 된 경험이 있으신가요?\n3. 하나님의 경고를 가볍게 여기지 않고 진지하게 받아들이려면 어떻게 해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-29', E'남유다에 대한 징계와 심판 (에스겔 7장)', E'에스겔 7장', E'에스겔이 전하는 심판의 메시지가 더욱 절박하고 긴급해집니다. "끝났도다 이 땅 사방의 일이 끝났도다"라는 하나님의 선포는 더 이상 돌이킬 수 없는 심판의 시간이 도래했음을 알려줍니다. 반복되는 ''끝''이라는 단어는 예루살렘에 임할 재앙의 확정성과 완전성을 강조합니다. 이제는 하나님의 긍휼을 기대할 수 없는 시점에 이르렀습니다.\n\n심판의 이유는 분명합니다. 이스라엘 백성들이 하나님께서 주신 은과 금으로 우상을 만들고, 그 화려한 장식으로 교만을 품었기 때문입니다. 하나님의 축복이 오히려 죄악의 도구가 되어버린 아이러니한 상황입니다. 그래서 하나님은 "그들의 은과 금이 능히 그들을 건지지 못하며"라고 선언하십니다. 재물이 구원의 수단이 될 수 없음을 분명히 하신 것입니다.\n\n심판의 날에는 모든 것이 무너집니다. 전쟁의 나팔이 울려도 싸우러 나갈 사람이 없고, 선지자에게서 묵시를 구해도 얻지 못하며, 제사장에게는 율법이, 장로에게는 지혜가 사라집니다. 종교적 지도자들조차 백성을 인도할 능력을 잃어버린 절망적인 상황이 펼쳐집니다. 밖에는 칼이, 안에는 전염병과 기근이 기다리는 진퇴양난의 상황에서 도망친 자들은 비둘기처럼 슬피 울 뿐입니다.\n\n그러나 이 무서운 심판 선언 속에서도 하나님의 궁극적인 목적이 드러납니다. "내가 여호와인 줄을 그들이 알리라"는 말씀이 반복되는 것은, 심판을 통해서라도 이스라엘이 참 하나님을 알기를 바라시는 하나님의 마음을 보여줍니다. 심판은 끝이 아니라 하나님을 다시 찾게 하시려는 아픈 사랑의 표현입니다.', E'오늘의 핵심\n하나님께서는 이스라엘의 완전한 심판을 선포하시면서도, 그 심판을 통해 당신이 참 하나님이심을 알게 하시려는 구원의 목적을 포기하지 않으십니다.\n\n묵상 질문\n1. 하나님의 축복을 우상으로 만들어버린 이스라엘처럼, 나도 은혜를 오용하고 있지는 않나요?\n2. 재물과 권력이 구원의 수단이 될 수 없다는 말씀이 오늘 내게 주는 교훈은 무엇인가요?\n3. 심판 속에서도 하나님을 알게 하시려는 그분의 마음을 어떻게 받아들이고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-30', E'하나님을 등진 예루살렘 (에스겔 1장)', E'에스겔 1장', E'바벨론 포로로 끌려간 지 5년째 되던 해, 그발 강가에서 제사장 에스겔에게 놀라운 환상이 임합니다. 북쪽에서 폭풍과 큰 구름이 몰려오는데, 그 속에서 번쩍이는 불과 빛이 사방을 비추고 있었습니다. 이 장엄한 광경은 하나님의 영광이 가까이 임하고 있음을 알리는 전조였습니다.\n\n환상 속에서 에스겔이 목격한 것은 네 생물의 형상이었습니다. 각 생물은 사람, 사자, 소, 독수리의 네 얼굴을 가지고 있었으며, 네 개의 날개와 사람의 손을 지니고 있었습니다. 이들은 영이 인도하는 대로 일제히 움직이되 결코 뒤돌아보지 않았습니다. 그들 곁에는 바퀴 안에 바퀴가 있는 신비로운 구조물이 있었는데, 온통 눈으로 가득 차 있어 하나님의 전지하심을 상징적으로 보여주고 있습니다.\n\n생물들의 머리 위에는 수정같이 맑은 궁창이 펼쳐져 있었고, 그 위로는 남보석 같은 보좌가 있었습니다. 그 보좌 위에는 사람의 모양을 한 형상이 앉아 계셨는데, 허리 위아래로 불과 같은 광채가 나며 무지개 같은 영광이 그를 둘러싸고 있었습니다. 이는 바로 여호와 하나님의 영광의 형상이었습니다.\n\n포로의 땅 바벨론, 그것도 이방의 강가에서 하나님의 영광을 목격한다는 것은 매우 의미심장한 일입니다. 예루살렘 성전에만 계시다고 생각했던 하나님께서 포로 된 백성들이 있는 곳까지 찾아오신 것입니다. 비록 심판으로 인해 고향을 떠나 있지만, 하나님은 여전히 그들과 함께 계시며 새로운 말씀을 주시려 하십니다. 에스겔이 그 영광 앞에 엎드린 것처럼, 우리도 어디에 있든지 임재하시는 하나님의 영광 앞에 겸손히 엎드려야 합니다.', E'오늘의 핵심\n포로의 땅 바벨론에서도 하나님의 영광은 당신의 백성을 찾아오셔서 새로운 소망의 메시지를 전하기 시작하십니다.\n\n묵상 질문\n1. 내가 있는 곳이 아무리 절망적이어도 하나님께서 찾아오실 수 있다는 사실이 어떤 위로가 되나요?\n2. 에스겔이 본 환상처럼 하나님의 영광과 위엄을 진정으로 경험한 적이 있나요?\n3. 하나님의 임재 앞에서 나는 어떤 자세로 서 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-01-31', E'하나님을 등진 예루살렘 (에스겔 2장)', E'에스겔 2장', E'바벨론 포로로 끌려간 지 5년째 되던 해, 그발 강가에서 에스겔은 놀라운 환상을 보게 됩니다. 하나님의 영광스러운 보좌 환상을 보고 엎드렸던 에스겔에게 하나님께서는 "인자야 네 발로 일어서라"고 명령하십니다. 그때 하나님의 영이 그에게 임하여 그를 일으켜 세우셨고, 에스겔은 비로소 하나님의 음성을 들을 수 있게 됩니다. \n\n하나님께서는 에스겔을 "패역한 백성, 나를 배반하는 자"들에게 보내신다고 말씀하십니다. 이스라엘 백성의 상태는 참으로 절망적이었습니다. 그들은 조상 대대로 하나님께 범죄하여 왔고, "얼굴이 뻔뻔하고 마음이 굳은" 상태에 이르렀습니다. 그럼에도 하나님은 포기하지 않으시고 에스겔을 보내어 "주 여호와의 말씀이 이러하시다"라는 메시지를 전하게 하십니다.\n\n놀라운 것은 하나님께서 미리 경고하신다는 점입니다. "그들이 듣든지 아니 듣든지" 상관없이 선지자를 보내신 것은, 그들이 나중에 핑계할 수 없도록 하기 위함이었습니다. 하나님은 에스겔에게 "가시와 찔레와 함께 있으며 전갈 가운데에 거주"하는 것 같은 어려움이 있을 것이라고 미리 알려주십니다. 사역의 환경은 결코 호의적이지 않을 것입니다. \n\n이 장면에서 가장 인상적인 것은 하나님께서 에스겔에게 두루마리를 먹으라고 명령하시는 장면입니다. 그 두루마리에는 "애가와 애곡과 재앙의 말"이 기록되어 있었습니다. 하나님의 말씀을 먹는다는 것은 그 말씀을 완전히 자신의 것으로 소화하여 전해야 한다는 의미입니다. 선지자는 자신의 말이 아닌, 하나님의 말씀만을 전해야 하는 사명을 받은 것입니다.', E'오늘의 핵심\n하나님께서는 패역한 백성에게 끝까지 말씀을 전하시기 위해 에스겔을 세우시고, 그에게 말씀을 먹여 준비시키십니다.\n\n묵상 질문\n1. 하나님의 영이 임하여 일으켜 세우실 때 비로소 들을 수 있었던 에스겔처럼, 내가 진정으로 하나님의 음성을 듣기 위해 필요한 자세는 무엇일까요?\n2. "듣든지 아니 듣든지" 말씀을 전하라고 하신 하나님의 마음을 생각해보면, 오늘 내가 포기하지 말아야 할 것은 무엇인가요?\n3. 애가와 애곡의 말씀까지도 먹고 전해야 했던 에스겔처럼, 내게 주어진 어려운 메시지나 사명은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-01', E'하나님을 등진 예루살렘 (에스겔 3장)', E'에스겔 3장', E'하나님께서 에스겔을 부르신 후, 그에게 특별한 명령을 주십니다. 두루마리를 먹으라는 명령이었습니다. 에스겔이 그 두루마리를 먹으니 입에서 꿀같이 달았다고 기록됩니다. 하나님의 말씀이 달다는 것은 그 말씀 자체의 선함과 아름다움을 의미하지만, 동시에 그 달콤함 속에는 이스라엘을 향한 심판의 메시지가 담겨 있었습니다.\n\n하나님은 에스겔을 언어가 다른 이방 민족이 아닌 이스라엘 족속에게 보내셨습니다. 그런데 하나님은 오히려 이방인들이 에스겔의 말을 더 잘 들었을 것이라고 말씀하십니다. 이스라엘은 하나님의 선택받은 백성이었지만, 그들의 이마가 굳고 마음이 굳어 하나님의 말씀을 듣고자 하지 않았습니다. 이에 하나님은 에스겔의 이마를 금강석같이 굳게 하셔서 반역하는 백성 앞에서도 담대히 말씀을 전할 수 있게 하셨습니다.\n\n에스겔이 포로 된 백성들이 거하는 델아빕에 도착했을 때, 그는 칠 일 동안 두려워 떨며 지냈습니다. 선지자로서의 무거운 사명감과 동족의 비참한 현실 앞에서 느낀 막막함이었을 것입니다. 이때 하나님은 에스겔을 이스라엘의 파수꾼으로 세우시며 그의 책임을 분명히 하십니다. 악인에게 경고하지 않으면 그 피 값을 에스겔에게서 찾겠다는 엄중한 말씀이었습니다.\n\n파수꾼의 사명은 단순히 말을 전하는 것이 아니라 생명을 구하는 것입니다. 하나님은 악인이든 의인이든 모두를 향해 깨우침의 메시지를 전하도록 하셨습니다. 그러나 동시에 하나님은 에스겔의 혀를 입천장에 붙게 하여 말 못하는 자가 되게 하신다고 말씀하십니다. 이는 하나님께서 원하실 때만 입을 열어 말하게 하시겠다는 뜻으로, 선지자의 메시지가 전적으로 하나님의 주권 아래 있음을 보여줍니다. 듣는 자는 듣고 듣지 않는 자는 듣지 않을 것이지만, 파수꾼된 에스겔은 반역하는 족속 앞에서도 하나님의 말씀을 신실하게 전해야 했습니다.', E'오늘의 핵심\n하나님께서는 에스겔을 이스라엘의 파수꾼으로 세우시며, 반역하는 백성에게 생명을 구하는 경고의 메시지를 전하도록 하셨습니다.\n\n묵상 질문\n1. 하나님의 달콤한 말씀이 때로는 쓴 심판의 메시지가 될 수 있음을 어떻게 이해하시나요?\n2. 파수꾼으로서 나에게 맡겨진 영혼들을 위해 어떻게 깨우침의 역할을 감당하고 있나요?\n3. 하나님의 말씀을 전할 때 사람들의 반응보다 하나님의 뜻에 순종하는 것이 왜 중요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-02', E'하나님을 등진 예루살렘 (에스겔 4장)', E'에스겔 4장', E'에스겔이 포로로 잡혀간 지 5년째 되던 때, 하나님께서는 그에게 특별한 방법으로 예루살렘의 운명을 보여주십니다. 토판에 예루살렘 성을 그리고 포위 공격의 모습을 재현하라는 명령은 단순한 그림이 아닌, 곧 닥칠 현실의 예고편이었습니다. 철판으로 만든 철벽은 하나님과 예루살렘 사이의 단절된 관계를 상징적으로 보여주고 있습니다.\n\n더욱 충격적인 것은 에스겔이 직접 몸으로 이스라엘과 유다의 죄악을 담당하는 모습입니다. 왼쪽으로 390일, 오른쪽으로 40일을 누워 있어야 한다는 명령은 북이스라엘과 남유다가 각각 지은 죄악의 무게를 보여줍니다. 하루가 일 년을 상징한다는 하나님의 말씀은 그들의 죄악이 얼마나 오랜 세월 축적되어 왔는지를 드러냅니다.\n\n포위된 성의 궁핍함도 에스겔의 행동을 통해 미리 보여집니다. 여섯 가지 곡물을 섞어 만든 떡과 제한된 양의 물은 포위 공격 중에 겪을 극심한 식량 부족을 예고합니다. 하루 이십 세겔(약 230g)의 음식과 육분의 일 힌(약 0.6리터)의 물은 생존을 위한 최소한의 양입니다. 인분으로 구워야 할 떡은 이방 땅에서 부정한 음식을 먹게 될 이스라엘의 비참한 처지를 보여주는데, 에스겔의 간청으로 쇠똥으로 대체되는 것은 하나님의 자비가 심판 중에도 여전히 남아있음을 보여줍니다.\n\n"내가 예루살렘에서 의뢰하는 양식을 끊으리니"(겔 4:16)라는 하나님의 선포는 그들이 의지하던 모든 것이 무너질 것을 예고합니다. 에스겔의 상징적 행동은 곧 닥칠 예루살렘의 파멸을 생생하게 보여주며, 하나님의 경고가 얼마나 절박한 것인지를 온 몸으로 전하고 있습니다.', E'오늘의 핵심\n하나님께서는 에스겔의 몸을 통해 예루살렘이 겪을 포위와 기근, 그리고 포로 생활의 고통을 미리 보여주시며 회개를 촉구하십니다.\n\n묵상 질문\n1. 하나님께서 이토록 구체적이고 생생하게 심판을 예고하시는 이유는 무엇일까요?\n2. 내 삶에서 하나님과 나 사이를 가로막는 ''철벽''은 무엇인가요?\n3. 오늘 나에게 필요한 최소한의 것만 주어진다면, 무엇이 가장 소중하다고 깨닫게 될까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-03', E'하나님을 등진 예루살렘 (에스겔 5장)', E'에스겔 5장', E'하나님께서는 에스겔에게 머리털과 수염을 깎아 삼등분하라는 특별한 명령을 내리십니다. 고대 이스라엘에서 머리털을 깎는 것은 극도의 수치와 애통을 의미했는데, 하나님의 선지자가 이런 행동을 하는 것은 충격적인 상징이었습니다. 깎은 머리털의 삼분의 일은 성읍 안에서 불사르고, 삼분의 일은 칼로 치고, 나머지 삼분의 일은 바람에 흩으라고 하십니다. 이는 예루살렘의 운명을 예표하는 것으로, 전염병과 기근으로 죽을 자, 칼에 죽을 자, 그리고 사방으로 흩어질 자들을 나타냅니다.\n\n하나님께서는 예루살렘을 "이방인 가운데" 두어 열방의 중심이 되게 하셨다고 말씀하십니다. 그러나 예루살렘은 오히려 주변 이방 민족들보다 더 악을 행했습니다. 하나님의 규례를 버리고 율례를 지키지 않았을 뿐 아니라, 심지어 이방인들의 규례대로도 행하지 않았다는 것은 그들의 타락이 극에 달했음을 보여줍니다. 특히 하나님의 성소를 "모든 미운 물건과 모든 가증한 일"로 더럽힌 것은 언약 백성으로서 가장 치명적인 배신이었습니다.\n\n심판의 내용은 참혹합니다. 아버지가 아들을 잡아먹고 아들이 그 아버지를 잡아먹는다는 표현은 예루살렘 포위 때 일어날 극심한 기근을 암시합니다. 하나님께서는 "전무후무하게" 벌을 내리겠다고 선언하시며, 예루살렘이 주변 민족들에게 "수치와 조롱거리"가 될 뿐 아니라 "두려움과 경고"가 되리라고 말씀하십니다. 이는 단순한 징벌이 아니라 열방을 향한 하나님의 공의로운 심판의 증거가 될 것입니다. 에스겔의 상징적 행동은 하나님께서 얼마나 철저하게 심판하실지를 생생하게 보여주는 예언적 표징이었습니다.', E'오늘의 핵심\n하나님께서는 에스겔의 상징적 행동을 통해 예루살렘이 받을 심판의 참혹함을 미리 보여주시며, 언약 백성이 하나님을 배신했을 때의 결과가 얼마나 비참한지를 경고하십니다.\n\n묵상 질문\n1. 하나님께서 예루살렘을 특별히 선택하셨는데도 왜 이방인보다 더 엄하게 심판하실까요?\n2. 내 삶에서 하나님의 은혜를 당연하게 여기고 있는 부분은 없을까요?\n3. 하나님의 경고를 무시할 때 어떤 결과가 따르는지 깨닫고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-05', E'하나님을 등진 예루살렘 (에스겔 6장)', E'에스겔 6장', E'하나님의 말씀이 에스겔에게 임하여 이스라엘 산들을 향한 엄중한 심판의 메시지를 전하게 하십니다. 이스라엘이 산당에서 우상을 섬기며 하나님과의 언약을 배반한 것에 대한 하나님의 진노가 선포되는 장면입니다. 하나님께서는 칼과 기근과 전염병을 통해 심판하실 것이며, 우상을 섬기던 제단들이 황폐해지고 그곳에서 경배하던 이들이 죽임을 당할 것이라고 말씀하십니다.\n\n특히 하나님께서는 "너희가 죽임을 당하여 엎드러지게 하여 내가 여호와인 줄을 너희가 알게 하려 함이라"(겔 6:7)고 말씀하시면서, 심판의 궁극적인 목적이 파멸 자체가 아니라 하나님을 알게 하는 데 있음을 분명히 하십니다. 이스라엘 백성들이 섬기던 우상들은 그들을 구원할 수 없으며, 오직 여호와만이 참 하나님이심을 깨닫게 하려는 것입니다.\n\n그러나 하나님의 은혜는 심판 가운데서도 멈추지 않습니다. 하나님께서는 "칼을 피하여 이방인들 중에 살아 남은 자가 있게 할지라"고 약속하십니다. 이 남은 자들은 포로로 잡혀가서도 하나님을 기억하며, 자신들이 음란한 마음으로 하나님을 떠나 우상을 섬긴 죄를 뉘우치게 될 것입니다. 하나님께서는 이들이 스스로 한탄하며 회개할 때, 비로소 여호와가 참 하나님이심을 알게 될 것이라고 말씀하십니다.\n\n에스겔을 통해 전해지는 이 메시지는 단순한 심판 선언이 아닙니다. 하나님께서는 손뼉을 치고 발을 구르며 탄식하라고 명하시는데, 이는 하나님 자신의 아픔과 탄식을 반영하는 것입니다. 우상숭배로 더럽혀진 산당과 제단, 푸른 나무 아래와 상수리나무 아래에서 분향하던 모든 곳이 심판의 장소가 될 것입니다. 그러나 이 모든 심판의 과정을 통해 하나님께서는 당신의 백성이 다시 돌아오기를 기다리고 계십니다. 광야에서부터 디블라까지 온 땅이 황폐해질지라도, 하나님의 궁극적인 목적은 "내가 여호와인 줄을 그들이 알리라"는 것입니다. 심판을 통해서라도 하나님을 알게 하시려는 이 간절한 사랑이 에스겔의 예언 속에 담겨 있습니다.', E'오늘의 핵심\n하나님께서는 우상숭배에 빠진 이스라엘을 심판하시지만, 그 심판의 목적은 파멸이 아니라 그들이 여호와만이 참 하나님이심을 알게 하려는 것입니다. 남은 자들을 통해 회개와 회복의 소망을 남겨두시는 하나님의 은혜가 나타납니다.\n\n묵상 질문\n1. 내 삶 속에서 하나님보다 더 의지하고 있는 ''우상''은 무엇인가요?\n2. 하나님의 징계를 통해 깨달은 하나님의 사랑을 경험한 적이 있나요?\n3. 심판 중에도 남은 자를 두시는 하나님의 마음을 느끼며, 오늘 내가 회개해야 할 것은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-06', E'하나님을 등진 예루살렘 (에스겔 7장)', E'에스겔 7장', E'이스라엘의 죄악이 극에 달하자 하나님께서는 더 이상 참지 않으시고 최후의 심판을 선포하십니다. "끝났도다 이 땅 사방의 일이 끝났도다"(겔 7:2)라는 반복된 선언은 이제 돌이킬 수 없는 종말의 때가 임박했음을 알려줍니다. 하나님의 진노가 쏟아지는 날, 그동안 이스라엘이 의지했던 모든 것들이 무너져 내립니다.\n\n특별히 주목할 것은 그들이 가장 소중하게 여기던 금과 은조차 아무런 도움이 되지 못한다는 점입니다. 오히려 그 화려한 장식품들로 우상을 만들어 하나님을 떠났던 이스라엘에게, 이제 그것들은 오물처럼 버려질 운명입니다. 재물이 구원이 될 수 없음을 보여주는 이 장면은 무엇을 의지하며 살아가는지 돌아보게 합니다.\n\n더욱 비극적인 것은 영적 지도력의 붕괴입니다. 선지자에게서 묵시를 구해도 헛되고, 제사장에게는 율법이 사라지며, 장로들에게는 지혜가 없어진다고 말씀하십니다. 하나님과의 관계가 끊어진 곳에서는 그 어떤 종교적 형식도 무의미해집니다. \n\n이 심판의 목적은 단순한 파괴가 아닙니다. "내가 여호와인 줄을 그들이 알리라"는 말씀이 반복되는 것은, 하나님께서 심판을 통해서라도 당신이 누구신지 알게 하시려는 간절한 마음을 드러냅니다. 징계 가운데서도 하나님은 여전히 자기 백성과의 관계 회복을 갈망하고 계십니다.\n\n포로기를 살았던 에스겔과 그의 동족들에게 이 메시지는 현재의 고난이 우연이 아니라 하나님의 공의로운 심판임을 깨닫게 했을 것입니다. 동시에 회개와 돌이킴의 기회가 아직 남아있음을 암시하는 희망의 메시지이기도 했습니다.', E'오늘의 핵심\n하나님의 최후 심판이 임할 때 세상의 그 어떤 것도 구원이 되지 못하며, 오직 여호와 하나님만이 참된 주권자이심을 깨닫게 됩니다.\n\n묵상 질문\n1. 내가 하나님보다 더 의지하고 있는 ''금과 은''은 무엇인가요?\n2. 영적 지도력이 무너진 시대에 나는 어디서 참된 지혜를 구하고 있나요?\n3. 하나님의 징계 속에서도 나를 향한 그분의 사랑을 발견한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-07', E'다시 회복될 이스라엘 (에스겔 36장)', E'에스겔 36장', E'포로로 끌려간 이스라엘 백성에게 하나님께서는 에스겔을 통해 놀라운 회복의 메시지를 전하십니다. 36장은 특별히 이스라엘의 산들을 향한 예언으로 시작됩니다. 황폐해진 이스라엘 땅이 주변 이방 나라들의 조롱거리가 되었지만, 하나님께서는 그 땅을 다시 회복시키실 것을 약속하십니다. \n\n하나님의 회복 계획에는 분명한 이유가 있었습니다. 이스라엘이 우상숭배와 불의로 땅을 더럽혔고, 그 결과 여러 나라로 흩어졌을 때, 이방인들은 "이들은 여호와의 백성이라도 여호와의 땅에서 떠난 자라"(겔 36:20)고 조롱했습니다. 하나님의 거룩한 이름이 이스라엘로 인해 더럽혀진 것입니다. 그래서 하나님께서는 자신의 거룩한 이름을 위하여 이스라엘을 회복시키기로 작정하셨습니다.\n\n이 회복의 약속은 단순히 고국으로의 귀환만을 의미하지 않습니다. 하나님께서는 맑은 물로 그들을 정결케 하시고, 돌같이 굳은 마음을 제거하여 부드러운 마음을 주시며, 새 영을 그들 속에 두어 하나님의 율례를 행하게 하실 것을 약속하십니다. 이는 외적인 회복을 넘어선 영적인 갱신의 약속입니다.\n\n특별히 주목할 것은 이 모든 회복이 이스라엘의 공로나 자격 때문이 아니라는 점입니다. 하나님께서는 두 번이나 "내가 이렇게 행함은 너희를 위함이 아니"라고 강조하십니다. 오히려 이스라엘은 자신들의 악한 행위를 기억하고 부끄러워해야 할 처지였습니다. 그럼에도 하나님께서는 자신의 거룩한 이름을 위하여, 그리고 언약에 신실하신 사랑 때문에 그들을 회복시키시는 것입니다. 황폐했던 땅이 에덴동산 같이 될 것이며, 이를 본 주변 나라들이 여호와께서 행하신 일임을 알게 될 것입니다.', E'오늘의 핵심\n하나님께서는 자신의 거룩한 이름을 위하여 이스라엘을 회복시키시며, 그들에게 새 마음과 새 영을 주어 진정한 영적 갱신을 이루실 것을 약속하십니다.\n\n묵상 질문\n1. 하나님께서 나를 회복시키시는 이유가 내 자격 때문이 아니라 그분의 은혜라는 것을 깨닫고 있나요?\n2. 내 삶에서 돌같이 굳은 마음을 부드럽게 바꾸어 달라고 기도해야 할 영역은 무엇인가요?\n3. 하나님의 이름이 내 삶을 통해 거룩히 여김을 받고 있나요, 아니면 오히려 욕을 받고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-08', E'다시 회복될 이스라엘 (에스겔 37장)', E'에스겔 37장', E'바벨론 포로기의 절망적인 현실 속에서 하나님은 에스겔에게 놀라운 환상을 보여주십니다. 하나님의 영이 에스겔을 데려간 곳은 마른 뼈들로 가득한 골짜기였습니다. 그 뼈들은 너무나 메말라 있어서 생명의 흔적이라곤 전혀 찾아볼 수 없었습니다. 이는 바로 당시 이스라엘 백성들의 영적 상태를 보여주는 것이었습니다. 나라는 멸망했고, 성전은 파괴되었으며, 백성들은 이방 땅에 흩어져 있었습니다. 그들의 입에서는 "우리의 뼈들이 말랐고 우리의 소망이 없어졌으니 우리는 다 멸절되었다"(겔 37:11)라는 절망의 탄식이 흘러나왔습니다.\n\n그러나 하나님은 이 죽음의 골짜기에서 생명의 역사를 일으키십니다. 에스겔이 하나님의 명령대로 대언하자 놀라운 일이 일어났습니다. 먼저 뼈들이 서로 연결되고, 힘줄이 생기며, 살이 오르고, 가죽이 덮였습니다. 그리고 마침내 하나님의 생기가 그들에게 들어가자 그들은 살아나서 극히 큰 군대가 되었습니다. 이 환상은 단순히 육체적 부활만을 의미하는 것이 아닙니다. 하나님께서 절망에 빠진 이스라엘을 영적으로 회복시키시고, 그들을 다시 하나님의 백성으로 세우실 것을 보여주는 것입니다.\n\n더 나아가 하나님은 두 막대기의 환상을 통해 분열되었던 남북 이스라엘이 하나로 통일될 것을 약속하십니다. 유다와 에브라임으로 나뉘어졌던 백성이 다시 한 나라가 되고, 한 왕의 통치를 받게 될 것입니다. 그 왕은 다윗의 계보를 잇는 메시아적 왕으로, 백성들을 하나님의 규례대로 인도할 것입니다. 하나님의 성소가 그들 가운데 영원히 거하며, 화평의 언약이 영원한 언약으로 세워질 것입니다. 이것이 절망 중에 있는 백성에게 주시는 하나님의 회복의 약속이었습니다.', E'오늘의 핵심\n마른 뼈처럼 완전히 죽어있던 이스라엘에게 하나님은 생명의 영을 불어넣으시어 다시 살리시고, 분열된 백성을 하나로 만드시며 영원한 언약 관계를 회복시켜 주십니다.\n\n묵상 질문\n1. 내 삶의 어떤 영역이 마른 뼈처럼 메말라 있으며, 하나님의 생기가 필요한가요?\n2. 하나님께서는 절망적인 상황에서도 회복의 소망을 주시는 분임을 믿고 있나요?\n3. 분열과 갈등으로 아픈 공동체를 위해 하나님의 치유와 연합을 구하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-09', E'다시 회복될 이스라엘 (에스겔 38장)', E'에스겔 38장', E'에스겔 38장은 마곡 땅의 곡에 대한 하나님의 심판 예언을 전하고 있습니다. 여기서 곡은 로스와 메섹과 두발의 왕으로, 바사와 구스와 붓, 그리고 고멜과 도갈마 족속을 이끌고 이스라엘을 공격하려는 강력한 연합군의 지도자로 등장합니다. 하나님께서는 이들을 "갈고리로 네 아가리를 꿰고"(겔 38:4) 끌어내신다고 말씀하십니다. 이는 하나님께서 그들의 악한 계획까지도 당신의 주권 아래 두고 계심을 보여줍니다.\n\n곡의 악한 의도는 평안히 거주하는 이스라엘 백성을 향한 침략 계획에서 분명히 드러납니다. 성벽도 없고 문이나 빗장도 없이 안전하게 살아가는 백성들을 보며, 곡은 물건을 겁탈하고 노략할 기회로 여깁니다. 이는 단순한 군사적 침공을 넘어, 약한 자를 착취하려는 탐욕과 폭력의 본성을 보여줍니다. 그러나 하나님께서는 이 모든 일이 "끝 날에" 일어날 것이며, 오히려 이를 통해 당신의 거룩함을 만방에 나타내실 계획임을 밝히십니다.\n\n특히 주목할 것은 하나님께서 곡의 침략을 허락하시는 목적입니다. 하나님은 "내가 너로 말미암아 이방 사람의 눈 앞에서 내 거룩함을 나타내어 그들이 다 나를 알게 하려 함이라"(겔 38:16)고 말씀하십니다. 악의 세력이 득세하는 것처럼 보이는 순간에도, 하나님께서는 그것을 통해 당신의 영광을 드러내시는 더 큰 계획을 가지고 계십니다. \n\n하나님의 심판은 압도적입니다. 큰 지진과 전염병, 폭우와 우박, 불과 유황으로 곡과 그의 연합군을 멸하실 것을 선포하십니다. 이는 출애굽 때 애굽에 내리신 재앙들을 연상시키며, 하나님께서 당신의 백성을 지키시는 전능하신 분이심을 재확인시켜 줍니다. 포로기를 살아가던 이스라엘 백성들에게 이 예언은 하나님께서 여전히 역사의 주관자이시며, 당신의 백성을 잊지 않으셨다는 확신을 주었을 것입니다.', E'오늘의 핵심\n하나님께서는 곡의 악한 침략 계획조차도 당신의 주권 아래 두시고, 오히려 이를 통해 모든 민족에게 당신의 거룩함과 능력을 나타내십니다.\n\n묵상 질문\n1. 오늘날 우리 주변에서 곡처럼 약한 자를 착취하려는 세력들을 어떻게 분별하고 있나요?\n2. 악이 득세하는 것처럼 보일 때에도 하나님의 주권을 신뢰하며 살아가고 있나요?\n3. 하나님께서 나의 삶을 통해 당신의 거룩함을 나타내시기 원하시는 영역은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-10', E'다시 회복될 이스라엘 (에스겔 39장)', E'에스겔 39장', E'하나님께서는 에스겔을 통해 곡의 최종적인 멸망을 선포하십니다. 이미 38장에서 예언된 곡의 심판이 39장에서는 더욱 구체적이고 완전한 모습으로 펼쳐집니다. 북쪽 끝에서 이스라엘을 침공하려던 곡의 군대는 이스라엘 산 위에서 처참하게 무너져 내립니다. 하나님께서는 곡의 활을 왼손에서 떨어뜨리고 화살을 오른손에서 떨어뜨리심으로써 그들의 모든 군사력을 무력화시키십니다. 한때 강대했던 곡의 군대는 사나운 새와 들짐승의 먹이가 되어 빈 들에 엎드러집니다.\n\n곡의 멸망은 단순한 군사적 패배가 아닙니다. 하나님께서는 "내가 여호와 곧 이스라엘의 거룩한 자인 줄을 민족들이 알리라"(겔 39:7)고 말씀하심으로써 이 심판의 궁극적 목적을 밝히십니다. 곡의 시체를 매장하는 데만 일곱 달이 걸리고, 그들의 무기는 일곱 해 동안 땔감으로 사용될 정도로 그 규모가 방대합니다. 이스라엘 백성은 전에 자기들을 약탈하던 자들의 것을 약탈하게 되는데, 이는 하나님의 공의로운 심판이 얼마나 철저한지를 보여줍니다.\n\n특별히 주목할 것은 하나님께서 이스라엘의 회복을 약속하시는 대목입니다. "내가 이제 내 거룩한 이름을 위하여 열심을 내어 야곱의 사로잡힌 자를 돌아오게 하며 이스라엘 온 족속에게 사랑을 베풀지라"(겔 39:25)는 말씀은 포로 생활로 지친 이스라엘 백성에게 놀라운 희망의 메시지였습니다. 하나님께서는 그들이 범죄함으로 인해 얼굴을 가리셨지만, 이제는 다시 그 얼굴을 돌리시고 성령을 부어주시겠다고 약속하십니다. 곡의 심판을 통해 드러난 하나님의 주권은 곧 이스라엘을 향한 변함없는 사랑과 신실하심의 증거였습니다.', E'오늘의 핵심\n하나님께서는 곡의 완전한 멸망을 통해 당신의 거룩하심을 만방에 드러내시고, 동시에 이스라엘의 회복과 성령 부음의 약속을 주십니다.\n\n묵상 질문\n1. 하나님의 심판이 악에 대해 얼마나 철저한지 보면서 내 삶의 죄악들을 어떻게 다루어야 할까요?\n2. 포로 생활 중에도 회복을 약속하시는 하나님의 신실하심이 오늘 내 상황에 어떤 위로가 됩니까?\n3. 하나님께서 성령을 부어주시겠다는 약속이 내 신앙생활에 어떤 소망을 주고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-12', E'환상 중에 본 새 예루살렘', E'에스겔 44장', E'에스겔이 본 새 성전의 환상은 동문으로 시작됩니다. 하나님께서 이미 그 문으로 들어가셨기에 다시는 열리지 않을 것이라는 선언은 그분의 영원한 임재를 약속하는 것입니다. 성전을 떠나셨던 하나님께서 다시 돌아오셔서 영원히 거하시겠다는 회복의 메시지가 담겨 있습니다.\n\n이어지는 말씀에서 하나님은 과거 이스라엘의 실패를 상기시키십니다. 그들은 마음과 몸에 할례받지 않은 이방인들을 성전에 들여 언약을 파기했고, 레위인들조차 우상을 따라 하나님을 떠났습니다. 성전의 거룩함이 무너진 것은 단순한 제도의 문제가 아니라 하나님과의 관계가 깨어진 결과였습니다.\n\n그러나 하나님은 완전한 단절이 아닌 회복의 길을 제시하십니다. 우상을 따랐던 레위인들에게도 성전에서 수종드는 직분을 허락하시되, 제사장 직분에는 제한을 두십니다. 반면 끝까지 성소의 직분을 지킨 사독의 자손들에게는 하나님께 가까이 나아가 수종드는 특권을 주십니다. 이는 과거의 충성이 잊히지 않았음을 보여주는 하나님의 신실하심입니다.\n\n새 성전의 제사장들에게 주어진 구체적인 규례들은 거룩함의 회복을 위한 것입니다. 그들은 백성에게 거룩한 것과 속된 것의 구별을 가르치고, 정결한 삶의 본이 되어야 했습니다. "내가 곧 그 기업이라"(겔 44:28)는 하나님의 선언은 제사장들이 세상의 기업이 아닌 하나님 자신을 기업으로 삼아야 함을 명확히 합니다.\n\n포로기의 백성들에게 이 환상은 절망 속의 희망이었습니다. 무너진 성전, 중단된 제사, 흩어진 백성의 현실 속에서도 하나님은 여전히 회복의 청사진을 그리고 계셨습니다. 오늘 우리의 삶에도 무너진 영역들이 있을 수 있습니다. 그러나 하나님은 우리의 실패로 끝나게 하지 않으시고, 다시 거룩함을 회복시키기 원하십니다. 지금 이 순간에도 신실하게 맡은 자리를 지키는 것이 미래의 영광스러운 회복을 준비하는 길입니다.', E'오늘의 핵심\n하나님은 과거의 실패를 기억하시면서도 회복의 길을 제시하시며, 끝까지 충성한 자들에게는 더 가까이 나아오는 특권을 허락하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 거룩함이 무너진 영역은 어디이며, 어떻게 회복할 수 있을까요?\n2. 지금 어려운 상황에서도 신실하게 지켜야 할 나의 자리는 무엇인가요?\n3. 하나님께서 "내가 곧 너의 기업"이라고 하실 때, 나는 무엇을 내려놓아야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-13', E'하나님의 본뜻 (에스겔 42장)', E'에스겔 42장', E'에스겔이 성전 환상 가운데 보게 된 것은 단순한 건축물의 설계도가 아니었습니다. 하나님께서는 성전 북쪽과 남쪽에 있는 제사장들의 방을 상세히 보여주시면서, 거룩한 공간이 어떻게 구별되어야 하는지를 가르쳐 주십니다. 이 방들은 "거룩한 방"으로, 여호와를 가까이하는 제사장들이 지성물을 먹는 곳이자 소제와 속죄제, 속건제의 제물을 보관하는 곳이었습니다.\n\n특히 주목할 것은 제사장들의 의복에 관한 규정입니다. 성소에서 수종들던 거룩한 의복을 입은 채로는 백성의 뜰로 나갈 수 없었습니다. 반드시 그 의복을 벗어 거룩한 방에 두고 다른 옷으로 갈아입어야 했습니다. 이는 거룩한 것과 일상적인 것의 경계를 분명히 하라는 하나님의 명령이었습니다.\n\n성전 측량의 마지막 장면도 의미심장합니다. 동서남북 각 오백 척씩 정확히 같은 크기로 측량된 성전의 사방 담은 "거룩한 것과 속된 것을 구별하는" 경계선이었습니다. 이전 성전이 무너진 이유 중 하나가 바로 이 경계의 붕괴였음을 생각할 때, 하나님께서는 새 성전에서 그 구별을 더욱 철저히 하고자 하신 것입니다.\n\n포로 된 백성에게 이런 환상을 보여주신 것은 단순히 미래의 건축 계획을 알려주시려는 것이 아니었습니다. 하나님께서는 "내가 여전히 거룩하며, 너희도 거룩해야 한다"는 변하지 않는 원칙을 가르치고 계셨습니다. 비록 지금은 이방 땅에 흩어져 있지만, 하나님의 백성으로서의 정체성을 잃지 말고, 거룩과 속된 것을 구별하는 삶을 살아가라는 메시지였습니다.\n\n오늘 우리의 삶에도 이런 구별이 필요합니다. 세상 속에 살지만 세상에 물들지 않고, 하나님의 거룩하심을 담아내는 그릇이 되어야 합니다. 내 삶의 어떤 영역에서 거룩한 것과 속된 것의 경계가 흐려지고 있는지 돌아보며, 다시 그 경계를 분명히 세워가시기 바랍니다.', E'오늘의 핵심\n하나님께서는 새 성전의 거룩한 공간과 제사장 규례를 통해, 거룩과 속된 것을 철저히 구별하는 삶의 원칙을 가르치십니다.\n\n묵상 질문\n1. 내 삶에서 거룩한 것과 일상적인 것의 경계가 흐려진 부분은 어디일까요?\n2. 하나님께서 나에게 요구하시는 ''구별된 삶''의 구체적인 모습은 무엇일까요?\n3. 포로 상황에서도 거룩함을 포기하지 않으신 하나님의 마음을 어떻게 받아들이고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-14', E'하나님의 본뜻 (에스겔 43장)', E'에스겔 43장', E'예루살렘이 함락되고 성전이 불탄 지 14년, 포로로 끌려간 에스겔에게 하나님께서 놀라운 환상을 보여주십니다. 동쪽 문으로 하나님의 영광이 들어오는데, 그 음성은 많은 물 소리 같고 땅은 그 영광으로 빛났습니다. 에스겔이 본 것은 단순한 건물이 아니라 하나님의 영광이 가득한 성전이었습니다.\n\n하나님께서는 "이는 내 보좌의 처소, 내 발을 두는 처소, 내가 이스라엘 족속 가운데에 영원히 있을 곳이라"(겔 43:7)고 선언하십니다. 이 말씀은 포로 생활로 절망하던 백성들에게 놀라운 약속이었습니다. 하나님이 다시 그들과 함께하시겠다는 것입니다. 그러나 과거를 돌아보게도 하십니다. 백성들이 성전 바로 곁에 우상의 문지방을 두고, 겨우 한 담만을 사이에 둔 채 가증한 일을 행했던 것을 지적하십니다.\n\n하나님께서는 제단의 치수와 정결 예식을 상세히 알려주십니다. 7일 동안 매일 속죄제물을 드려 제단을 정결하게 하라고 명령하십니다. 이는 단순한 의식이 아닙니다. 거룩하신 하나님과 만나기 위해서는 철저한 회개와 정결함이 필요하다는 가르침입니다. 속죄의 피가 제단의 네 뿔과 모퉁이, 가장자리에 발라져야 했습니다. 구석구석 남김없이 정결하게 되어야 한다는 뜻입니다.\n\n오늘 우리에게도 하나님은 같은 질문을 하십니다. 우리 마음의 성전은 어떠한가요? 하나님의 보좌 바로 곁에 세상의 가치관과 욕망의 문지방을 슬쩍 세워두고 있지는 않은지요. 하나님께서는 우리와 영원히 함께하기를 원하십니다. 그러나 그분의 거룩하심과 우리의 죄악은 양립할 수 없습니다. 회개와 정결함으로 나아갈 때, 하나님의 영광이 우리 삶에 충만하게 임할 것입니다.', E'오늘의 핵심\n하나님께서는 무너진 성전의 회복을 약속하시며, 백성들이 철저히 회개하고 정결하게 될 때 그들 가운데 영원히 거하시겠다고 선언하십니다.\n\n묵상 질문\n1. 절망적인 상황에서도 하나님이 회복의 비전을 보여주신다는 사실이 내게 어떤 위로가 됩니까?\n2. 내 삶에서 하나님의 거룩함 바로 곁에 두고 있는 ''세상의 문지방''은 무엇일까요?\n3. 하나님과의 온전한 만남을 위해 오늘 내가 정결하게 해야 할 영역은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-15', E'여호와의 영광으로 가득 찬 성전 (에스겔 44장)', E'에스겔 44장', E'에스겔이 본 새 성전의 환상 중에서도 44장은 특별히 성전의 거룩함과 제사장 직분의 회복에 초점을 맞추고 있습니다. 먼저 동쪽 문이 영원히 닫히는 장면이 나타나는데, 이는 여호와 하나님께서 그 문으로 들어오셨기 때문입니다. 거룩하신 하나님이 지나가신 곳은 다시는 속된 용도로 사용될 수 없다는 것을 보여줍니다.\n\n하나님은 과거 이스라엘의 실패를 구체적으로 지적하십니다. 그들은 마음과 몸에 할례받지 않은 이방인들을 성소에 들어오게 하여 성전을 더럽혔고, 심지어 성물을 지키는 직분까지 그들에게 맡겼습니다. 우상을 따라간 레위인들도 그 책임에서 자유롭지 못했습니다. 그들은 성전에서 수종들 수는 있지만, 더 이상 제사장의 직분은 행할 수 없게 됩니다.\n\n그러나 이 심판의 말씀 가운데서도 은혜의 빛이 비칩니다. 사독의 자손들은 이스라엘이 하나님을 떠날 때에도 성소의 직분을 신실하게 지켰기에, 하나님께 가까이 나아가 제사장의 직무를 계속 수행할 특권을 얻게 됩니다. 하나님은 어두운 시대에도 당신께 충성한 이들을 기억하시고 귀하게 여기십니다.\n\n새 성전의 제사장들에게 주어진 규례들은 매우 구체적입니다. 그들의 의복부터 머리 모양, 결혼 규정, 그리고 거룩한 것과 속된 것을 구별하여 가르치는 사명까지 세세하게 규정됩니다. 특별히 "내가 곧 그 기업이라"는 하나님의 선언은 제사장들에게 땅의 기업이 없는 대신 하나님 자신이 그들의 기업이 되신다는 놀라운 약속입니다.\n\n오늘날 우리도 왕 같은 제사장으로 부름받았습니다. 세상과 구별된 거룩한 삶을 살며, 하나님과 사람 사이에서 중보하는 사명을 받았습니다. 사독의 자손들처럼 시대가 어둡다 해도 맡은 자리를 지키는 신실함이 필요합니다. 하나님은 지금도 당신을 향한 충성을 기억하시고 귀하게 여기십니다.', E'오늘의 핵심\n하나님은 과거의 실패를 지적하시면서도 신실했던 사독의 자손들을 기억하시고, 새 성전에서 제사장 직분을 회복시키시며 거룩한 삶의 기준을 제시하십니다.\n\n묵상 질문\n1. 어두운 시대에도 자리를 지킨 사독의 자손들처럼, 나는 맡겨진 자리에서 신실하게 섬기고 있나요?\n2. 하나님이 나의 기업이 되신다는 것은 어떤 의미이며, 나는 그것을 어떻게 경험하고 있나요?\n3. 거룩한 것과 속된 것을 구별하여 가르치는 제사장의 사명이 오늘 나의 삶에서는 어떻게 실천될 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-16', E'여호와의 영광으로 가득 찬 성전 (에스겔 45장)', E'에스겔 45장', E'거룩한 구역의 측량으로 시작되는 에스겔 45장은 회복될 이스라엘의 새로운 질서를 보여줍니다. 포로의 땅에서 듣는 이 말씀은 단순한 토지 분배 계획이 아니라, 하나님께서 다시 그들과 함께 거하실 거룩한 공동체의 청사진입니다.\n\n하나님은 먼저 성소를 위한 거룩한 땅을 구별하십니다. 그 중심에는 "지극히 거룩한" 성소가 자리하고, 그 주변으로 제사장들과 레위인들의 거주지가 배치됩니다. 이어서 성읍의 기지와 왕의 땅이 정해지는데, 특별히 왕의 영역은 동서로 길게 뻗어 있으면서도 다른 지파의 땅과 균형을 이루도록 배치됩니다. 이는 과거 왕들이 백성의 땅을 빼앗고 압제했던 역사와는 완전히 다른 새로운 통치 질서를 보여줍니다.\n\n더욱 주목할 만한 것은 하나님께서 "이스라엘의 통치자들아 너희에게 만족하니라"(겔 45:9)고 말씀하시며 포악과 겁탈을 그치라고 명령하시는 장면입니다. 공정한 저울과 정확한 도량형을 사용하라는 구체적인 지침은 일상의 거래에서부터 정의가 실현되어야 함을 가르칩니다. 하나님의 거룩함은 성전 안에만 머물지 않고 시장터의 저울추에까지 미쳐야 하는 것입니다.\n\n또한 예물과 제사에 관한 규정들은 백성과 왕이 함께 책임을 나누는 구조로 되어 있습니다. 백성은 정해진 예물을 드리고, 왕은 그것으로 공동체를 위한 제사를 준비합니다. 이는 예배가 개인의 종교 행위가 아니라 공동체 전체가 참여하는 연대의 행위임을 보여줍니다.\n\n회복의 비전 속에서 하나님은 거룩함과 정의, 예배와 일상, 개인과 공동체를 하나로 엮어내십니다. 오늘 우리의 삶에서도 하나님의 거룩함이 예배당을 넘어 일터와 시장, 가정과 사회로 흘러가기를 소망합니다.', E'오늘의 핵심\n하나님께서는 새로운 이스라엘 공동체의 질서를 통해 거룩함과 정의가 일상 속에서 실현되는 나라를 꿈꾸고 계십니다.\n\n묵상 질문\n1. 내 삶의 어떤 영역에 하나님의 거룩함이 더 깊이 스며들어야 할까요?\n2. 일상의 작은 거래에서도 정의와 공정을 실천하고 있나요?\n3. 나의 예배가 공동체와 함께하는 연대의 행위가 되려면 어떤 변화가 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-17', E'여호와의 영광으로 가득 찬 성전 (에스겔 46장)', E'에스겔 46장', E'에스겔이 본 새 성전의 예배 규례는 하나님께서 그의 백성과 어떻게 만나기를 원하시는지를 구체적으로 보여줍니다. 안식일과 초하루에 열리는 동문을 통해 군주가 들어와 예배하고, 백성들도 함께 하나님 앞에 나아옵니다. 여기서 주목할 것은 군주가 특별한 위치에서 예배하지만, 백성들과 함께 예배드린다는 점입니다. 그는 백성들이 들어올 때 함께 들어오고, 나갈 때 함께 나갑니다.\n\n새 성전의 예배에서는 정해진 제물이 있습니다. 안식일에는 흠 없는 어린 양 여섯 마리와 숫양 한 마리, 초하루에는 수송아지와 어린 양들을 드립니다. 매일 아침마다 드리는 번제는 영원한 규례로 정해졌습니다. 이러한 규칙적이고 지속적인 예배는 하나님과의 관계가 일회적인 것이 아니라 지속적이고 규칙적인 만남임을 가르쳐줍니다.\n\n특별히 의미 있는 것은 군주가 자신의 기업을 나누는 방식입니다. 아들에게 준 것은 영원한 기업이 되지만, 종에게 준 것은 희년에 다시 돌아옵니다. 또한 군주는 백성의 기업을 빼앗을 수 없습니다. 이는 하나님 나라의 공의로운 통치 원리를 보여줍니다. 권력자라 할지라도 백성의 권리를 함부로 침해할 수 없으며, 각자의 기업은 보호받아야 합니다.\n\n성전 구석구석에 마련된 부엌들은 제사장들이 백성의 제물을 삶는 곳입니다. 거룩한 예배가 일상적인 식사 준비와 연결되어 있다는 것은 우리의 신앙이 특별한 순간에만 머물러서는 안 됨을 가르쳐줍니다. 하나님께 드리는 예배는 우리의 일상 전체와 연결되어야 합니다.\n\n오늘날 우리는 어떻게 규칙적으로 하나님을 만나고 있습니까? 주일예배뿐 아니라 매일의 삶 속에서 하나님과의 만남이 이루어지고 있는지 돌아보게 됩니다. 또한 우리가 가진 것을 나누는 방식은 공의로운지, 다른 이들의 권리를 존중하며 살아가는지 성찰해 볼 때입니다.', E'오늘의 핵심\n새 성전의 예배 규례는 하나님과 백성의 규칙적인 만남을 강조하며, 군주와 백성이 함께하는 예배와 공의로운 기업 분배의 원칙을 제시합니다.\n\n묵상 질문\n1. 나는 하나님과의 만남을 규칙적이고 지속적으로 유지하고 있나요?\n2. 내가 가진 권한이나 소유를 다른 이들과 나눌 때 공의롭게 하고 있나요?\n3. 거룩한 예배가 일상의 삶과 어떻게 연결되어 있다고 생각하나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-19', E'다니엘의 환상과 해석 (다니엘 7장)', E'다니엘 7장', E'바벨론 왕 벨사살 원년, 다니엘은 침상에서 놀라운 환상을 보게 됩니다. 바다에서 올라온 네 짐승의 환상은 앞으로 일어날 제국들의 흥망성쇠를 보여주는 것이었습니다. 첫째 짐승은 독수리 날개를 가진 사자로, 날개가 뽑히고 사람처럼 서게 되는 모습은 교만했던 느부갓네살이 낮아진 후 회복된 바벨론을 상징합니다. 둘째 짐승인 곰은 메대와 바사를, 넷째 날개를 가진 표범은 신속하게 세계를 정복한 헬라 제국을 가리킵니다. 그리고 철 이빨을 가진 무서운 넷째 짐승은 로마 제국을 예표하는데, 특히 그 가운데서 나온 작은 뿔은 하나님을 대적하며 성도들을 핍박할 적그리스도의 모습을 보여줍니다.\n\n그러나 환상의 절정은 "옛적부터 항상 계신 이"가 보좌에 앉으시는 장면입니다. 불꽃 같은 보좌에서 심판이 시작되고, 교만한 작은 뿔은 멸망당합니다. 그리고 "인자 같은 이"가 구름을 타고 와서 영원한 나라를 받는 장면은 메시아의 궁극적 승리를 보여줍니다. 세상 제국들이 아무리 강해 보여도 결국 하나님의 주권 아래 있으며, 마침내 "지극히 높으신 이의 성도들"이 영원한 나라를 받게 될 것입니다.\n\n다니엘은 이 환상으로 인해 번민하고 얼굴빛이 변했지만, 이 일을 마음에 간직했습니다. 격동의 시대를 살아가는 하나님의 백성에게 주시는 위로와 소망의 메시지였기 때문입니다.', E'오늘의 핵심\n하나님께서는 다니엘에게 네 짐승의 환상을 통해 세상 제국들의 흥망성쇠와 함께 궁극적으로 하나님의 나라가 영원히 서게 될 것을 보여주십니다.\n\n묵상 질문\n1. 세상의 강한 권세 앞에서도 하나님의 주권을 신뢰하고 계신가요?\n2. "인자 같은 이"가 받은 영원한 나라를 바라보며 어떤 소망을 갖게 되나요?\n3. 번민스러운 현실 속에서도 하나님의 약속을 마음에 간직하고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-20', E'다니엘의 환상과 해석 (다니엘 8장)', E'다니엘 8장', E'다니엘에게 첫 번째 환상이 나타난 지 2년 후, 하나님께서는 그에게 또 다른 환상을 보여주십니다. 이번에는 숫양과 숫염소의 환상이었습니다. 다니엘이 본 두 뿔 가진 숫양은 메대와 바사 제국을 상징하는 것이었고, 서쪽에서 날아온 숫염소는 헬라 제국을 가리키는 것이었습니다. 특히 숫염소의 큰 뿔은 알렉산더 대왕을, 그것이 꺾인 후 난 네 뿔은 그의 제국이 네 부분으로 나뉘어질 것을 예언하는 것이었습니다.\n\n이 환상의 핵심은 단순히 미래 역사의 전개를 보여주는 데 있지 않았습니다. 하나님께서는 제국들의 교만과 그들이 하나님의 백성을 핍박하는 모습을 보여주시면서, 결국 인간의 권력이 얼마나 허무한 것인지를 깨닫게 하십니다. 작은 뿔로 상징된 통치자는 "스스로 높아져서 군대의 주재를 대적하며"(단 8:11) 하나님을 대적하기까지 하지만, 결국 "사람의 손으로 말미암지 아니하고 깨지리라"는 말씀처럼 하나님의 심판을 피할 수 없게 됩니다.\n\n가브리엘 천사가 나타나 이 환상의 의미를 설명해 주었을 때, 다니엘은 그 무게를 감당하기 어려워 얼굴을 땅에 대고 엎드렸습니다. 환상을 통해 하나님의 뜻을 깨달은 후, 다니엘은 여러 날 동안 앓아누웠습니다. 그러나 회복된 후 그가 보여준 모습은 우리에게 깊은 교훈을 줍니다. 그는 곧바로 일어나 왕의 일을 보았던 것입니다.\n\n다니엘의 이러한 모습은 깊은 영성과 현실적 책임감이 조화를 이룬 신앙인의 삶을 보여줍니다. 하나님의 계시를 받을 만큼 깊은 영성을 지녔으면서도, 동시에 이방 왕국에서 충성스럽게 자신의 직무를 수행하는 모습은 오늘날 우리가 추구해야 할 신앙의 모델입니다. 하나님 나라의 비전을 품으면서도 현실 속에서 성실하게 살아가는 것, 이것이 다니엘이 우리에게 보여주는 균형 잡힌 신앙생활의 모습입니다.', E'오늘의 핵심\n하나님께서는 다니엘에게 제국들의 흥망성쇠를 보여주시면서 인간 권력의 한계와 하나님의 주권을 깨닫게 하십니다. 환상을 본 후에도 현실의 책임을 다하는 다니엘의 모습은 균형 잡힌 신앙생활의 모범을 보여줍니다.\n\n묵상 질문\n1. 하나님께서 다니엘에게 미래의 역사를 보여주신 이유는 무엇일까요?\n2. 깊은 영적 체험 후에도 일상의 책임을 성실히 감당하는 삶을 살고 있나요?\n3. 세상 권력의 교만함을 보면서도 하나님의 주권을 신뢰하고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-21', E'다시 태어나는 공동체, 재건세대 (에스라 1장)', E'에스라 1장', E'하나님의 백성이 바빌론에 포로로 끌려간 지 70년의 세월이 흘렀습니다. 예레미야를 통해 약속하신 그 기간이 정확히 채워졌을 때, 놀라운 일이 일어납니다. 이방 제국의 왕 고레스가 "하늘의 하나님 여호와께서 세상 모든 나라를 내게 주셨고 나에게 명령하사 유다 예루살렘에 성전을 건축하라 하셨나니"(스 1:2)라고 선포한 것입니다. 하나님께서는 이방 왕의 마음을 감동시켜 당신의 뜻을 이루어 가십니다.\n\n고레스의 조서는 단순히 귀환 허락에 그치지 않았습니다. 그는 유대인들이 예루살렘으로 돌아가 성전을 재건하도록 명령하며, 주변 사람들이 은과 금과 물품으로 그들을 도우라고까지 지시합니다. 더욱 놀라운 것은 느부갓네살이 예루살렘 성전에서 약탈해 간 성전 기물들을 모두 돌려주었다는 사실입니다. 금과 은으로 된 그릇 5,400개가 유다 총독 세스바살에게 인계되어 예루살렘으로 운반됩니다.\n\n이 귀환의 물결에 누가 동참했을까요? 에스라는 "그 마음이 하나님께 감동을 받고 올라가서 예루살렘에 여호와의 성전을 건축하고자 하는 자가 다 일어나니"라고 기록합니다. 바빌론에서 이미 정착하여 안정된 삶을 누리던 많은 이들이 있었을 것입니다. 그러나 하나님의 감동하심을 받은 이들은 기득권을 포기하고 황폐한 고국으로 돌아가는 길을 선택했습니다. 유다와 베냐민 족장들, 제사장들과 레위인들이 앞장섰고, 일반 백성들도 합류했습니다.\n\n70년이라는 긴 포로 생활은 이스라엘 백성에게 깊은 영적 성찰의 시간이 되었습니다. 그들은 우상숭배와 불순종의 결과가 무엇인지 뼈저리게 경험했고, 이제 하나님께서 주시는 새로운 기회 앞에 서게 되었습니다. 고레스라는 이방 왕을 통해서라도 당신의 백성을 회복시키시는 하나님의 신실하심과 주권적 역사가 에스라 1장에 생생히 드러납니다.', E'오늘의 핵심\n하나님께서는 정하신 때에 이방 왕 고레스의 마음을 감동시켜 포로 된 백성을 귀환시키시고, 성전 재건의 새로운 장을 여십니다.\n\n묵상 질문\n1. 70년의 약속을 정확히 지키시는 하나님의 신실하심을 어떻게 경험하고 계신가요?\n2. 안정된 삶을 포기하고 하나님의 일에 동참한 사람들처럼, 당신은 무엇을 결단해야 합니까?\n3. 하나님께서 뜻밖의 사람과 방법으로 일하실 때, 그것을 알아볼 영적 민감함이 있으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-22', E'다시 태어나는 공동체, 재건세대 (에스라 2장)', E'에스라 2장', E'방대한 귀환자 명단이 에스라 2장에 빼곡히 기록되어 있습니다. 바벨론 포로 생활 70년을 마치고 고국으로 돌아가는 42,360명의 이름과 숫자가 하나하나 새겨져 있는 것입니다. 이 명단은 단순한 인구 통계가 아니라, 하나님의 신실하신 약속 이행의 증거이며, 믿음을 지킨 사람들의 거룩한 기록입니다. \n\n스룹바벨과 예수아의 인도 아래 귀환하는 이들 중에는 제사장들과 레위인들, 성전 봉사자들과 일반 백성들이 모두 포함되어 있었습니다. 특별히 주목할 점은 이들이 각자의 조상의 고향과 성읍을 정확히 기억하고 있었다는 사실입니다. 70년이라는 긴 세월 동안 바벨론에서 태어나고 자란 2, 3세대들임에도 불구하고, 그들은 자신들의 정체성과 뿌리를 잊지 않았던 것입니다.\n\n하나님께서는 이 귀환자 명단을 통해 우리에게 중요한 진리를 보여주십니다. 하나님은 당신의 백성 한 사람 한 사람을 기억하고 계시며, 그들의 이름을 아신다는 것입니다. "온 회중의 합계가 사만 이천삼백육십 명"(스 2:64)이라는 기록은 하나님께서 얼마나 정확하게 당신의 백성을 세고 계시는지를 보여줍니다.\n\n귀환 공동체 가운데는 자신의 계보를 증명할 수 없어 제사장 직무에서 제외된 사람들도 있었습니다. 이는 하나님의 거룩한 직무를 수행하는 데 있어서 정체성의 확실함이 얼마나 중요한지를 보여주는 대목입니다. 동시에 이들은 우림과 둠밈을 가진 제사장이 일어날 때까지 기다리라는 지시를 받았는데, 이는 하나님께서 때가 되면 모든 것을 분명히 하실 것이라는 소망을 품게 합니다.\n\n귀환자들이 예루살렘 성전 터에 도착했을 때, 그들은 자발적으로 성전 재건을 위한 예물을 드렸습니다. 금 육만 천 다릭과 은 오천 마네, 그리고 제사장의 옷 백 벌은 그들이 바벨론에서 어렵게 모은 재산이었을 것입니다. 그러나 그들은 기쁨으로 이를 드렸는데, 이는 하나님의 성전 재건이라는 거룩한 사명 앞에서 개인의 소유를 아끼지 않는 헌신의 모습을 보여줍니다.', E'오늘의 핵심\n하나님은 당신의 백성 한 사람 한 사람의 이름을 기억하시며, 포로 생활을 끝내고 귀환하는 42,360명의 명단을 통해 신실하신 언약의 성취를 보여주십니다.\n\n묵상 질문\n1. 70년의 포로 생활에도 정체성을 잃지 않은 귀환자들처럼, 나는 하나님의 백성으로서의 정체성을 어떻게 지키고 있나요?\n2. 하나님께서 내 이름을 기억하고 계신다는 사실이 오늘 나에게 어떤 위로와 힘이 되나요?\n3. 성전 재건을 위해 기쁨으로 헌금한 귀환자들처럼, 나는 하나님의 일에 어떤 마음으로 참여하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-23', E'오직 성령의 능력으로 다시 (스가랴 1장)', E'스가랴 1장', E'다리오 왕 제2년, 바벨론 포로에서 돌아온 지 18년이 지났지만 성전 재건은 여전히 중단된 채 방치되어 있었습니다. 하나님께서는 이런 상황 가운데 스가랴를 부르셔서 회개와 회복의 메시지를 전하게 하십니다. 스가랴가 전한 첫 번째 메시지는 조상들의 실패를 거울삼아 하나님께로 돌아오라는 간절한 호소였습니다.\n\n하나님께서는 "너희는 내게로 돌아오라"(슥 1:3)고 반복하여 말씀하십니다. 과거 조상들이 선지자들의 경고를 무시하고 악한 길에서 돌이키지 않았던 것처럼, 지금의 백성들도 성전 재건을 포기하고 자기 집 짓기에만 몰두하고 있었습니다. 그러나 하나님의 말씀과 법도는 결국 그들에게 임했고, 조상들은 뒤늦게야 하나님의 심판이 정당했음을 인정해야 했습니다.\n\n스가랴가 본 환상은 하나님의 마음을 더욱 분명하게 보여줍니다. 온 땅을 순찰하는 천사들의 보고에 따르면 열방은 평안하고 조용했지만, 정작 하나님의 백성은 여전히 고난 가운데 있었습니다. 여호와의 천사가 70년이나 지속된 예루살렘의 고통을 호소하자, 하나님께서는 선한 말씀, 위로하는 말씀으로 응답하십니다. 그 내용은 예루살렘과 시온을 향한 하나님의 뜨거운 질투와 사랑, 그리고 안일한 열방에 대한 진노였습니다.\n\n이어지는 네 뿔과 네 대장장이의 환상은 이스라엘을 흩어지게 한 열방의 권세가 결국 무너질 것임을 보여줍니다. 하나님께서는 당신의 백성을 괴롭힌 나라들을 심판하시고, 예루살렘을 다시 택하여 회복시키실 것입니다. 성전이 재건되고, 성읍들이 번영하며, 하나님의 위로가 시온에 임할 것입니다. 이는 단순한 건축 공사의 재개가 아니라, 하나님과 백성 사이의 관계가 회복되는 영적 갱신의 시작을 의미했습니다.', E'오늘의 핵심\n하나님께서는 70년의 징계 후에도 여전히 당신의 백성을 사랑하시며, 그들이 돌아오기만 하면 예루살렘을 회복시키고 열방을 심판하실 것을 약속하십니다.\n\n묵상 질문\n1. 조상들의 실패에서 배워야 할 교훈은 무엇이며, 나는 그 실수를 반복하고 있지 않나요?\n2. 하나님께서 "내게로 돌아오라"고 부르실 때, 나를 주저하게 만드는 것은 무엇인가요?\n3. 오랜 침묵과 고난 속에서도 하나님의 회복 약속을 어떻게 붙잡고 살아갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-24', E'오직 성령의 능력으로 다시 (스가랴 2장)', E'스가랴 2장', E'포로기를 거쳐 돌아온 백성들은 폐허가 된 예루살렘을 재건하는 일에 많은 어려움을 겪고 있었습니다. 무너진 성벽과 황폐한 땅을 바라보며 과연 이곳이 회복될 수 있을까 하는 의구심이 들었을 것입니다. 바로 이때 하나님께서는 스가랴에게 세 번째 환상을 보여주십니다. 측량줄을 든 한 사람이 예루살렘의 너비와 길이를 재려고 하는데, 천사가 달려가 그를 막으며 놀라운 말씀을 전합니다. 예루살렘은 성곽 없는 성읍이 될 것이라는 선언이었습니다.\n\n당시 성곽은 도시를 보호하는 필수적인 방어 수단이었기에 성곽 없는 성읍이란 상상하기 어려운 일이었습니다. 그러나 하나님께서는 친히 불로 둘러싼 성곽이 되시고 그 가운데서 영광이 되시겠다고 약속하십니다. 인간이 만든 물리적 성벽보다 하나님의 임재 자체가 더 완전한 보호가 된다는 놀라운 선언입니다. 더 나아가 하나님께서는 아직 바벨론에 남아있는 백성들에게 속히 돌아올 것을 명하십니다. "너희를 범하는 자는 그의 눈동자를 범하는 것이라"는 말씀은 하나님께서 당신의 백성을 얼마나 소중히 여기시는지를 보여줍니다.\n\n회복의 약속은 이스라엘에만 국한되지 않습니다. 그 날에 많은 나라가 여호와께 속하여 하나님의 백성이 될 것이라는 원대한 비전이 제시됩니다. 예루살렘은 단지 유대인만의 도시가 아닌 만민이 하나님께 나아오는 구원의 중심지가 될 것입니다. 이 모든 일의 중심에는 하나님께서 친히 그들 가운데 거하시겠다는 임재의 약속이 있습니다. 모든 육체가 여호와 앞에서 잠잠해야 할 것은 하나님께서 거룩한 처소에서 일어나 친히 일하시기 때문입니다.', E'오늘의 핵심\n하나님께서는 무너진 예루살렘을 단순히 재건하는 것이 아니라, 친히 불 성곽이 되시고 그 가운데 영광으로 거하시며 만민을 구원하는 새로운 차원의 회복을 약속하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 임재가 가장 확실한 보호가 된다는 것을 어떻게 경험하고 있나요?\n2. 하나님께서 나를 눈동자같이 지키신다는 약속이 오늘 나에게 어떤 위로와 힘이 되나요?\n3. 하나님의 구원이 모든 민족에게 열려있다는 비전을 품고 내가 할 수 있는 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-26', E'오직 성령의 능력으로 다시 (스가랴 3장)', E'스가랴 3장', E'포로 귀환 후 성전 재건의 중책을 맡은 대제사장 여호수아의 모습을 통해 하나님의 놀라운 은혜가 펼쳐집니다. 스가랴가 본 환상 속에서 여호수아는 더러운 옷을 입고 여호와의 천사 앞에 서 있었고, 사탄은 그의 오른편에서 그를 고소하고 있었습니다. 이 장면은 단순히 개인의 죄 문제를 넘어서서, 바벨론 포로 생활로 인해 더럽혀진 이스라엘 전체의 영적 상태를 상징적으로 보여줍니다.\n\n그러나 하나님께서는 사탄의 고소를 단호히 거절하시며 "이는 불에서 꺼낸 그슬린 나무가 아니냐"라고 말씀하십니다. 불에 그슬렸지만 완전히 타지 않고 건져낸 나무처럼, 이스라엘은 비록 심판의 불을 거쳤지만 하나님의 은혜로 보존되었음을 선포하신 것입니다. 하나님은 여호수아의 더러운 옷을 벗기고 아름다운 옷과 정결한 관을 씌워주심으로써, 죄악을 제거하고 새로운 신분을 부여하십니다. 이는 인간의 노력이 아닌 하나님의 일방적인 은혜로 이루어지는 구원을 보여줍니다.\n\n더 나아가 하나님께서는 여호수아를 통해 메시아에 대한 약속을 주십니다. "내가 내 종 싹을 나게 하리라"는 선언과 함께, 일곱 눈이 있는 한 돌에 대한 환상은 장차 오실 메시아를 통한 완전한 구원을 예고합니다. 특별히 "이 땅의 죄악을 하루에 제거하리라"는 약속은 십자가에서 단번에 이루어질 구속을 가리킵니다. 포로 귀환 공동체의 영적 회복은 단지 성전 건물의 재건에 있지 않고, 하나님께서 주시는 죄 사함과 새로운 시작의 은혜에 있음을 깨닫게 합니다. 이렇게 하나님은 실패와 좌절 속에서도 당신의 백성을 포기하지 않으시고, 그들을 정결케 하시며 새로운 사명으로 부르십니다.', E'오늘의 핵심\n하나님께서는 죄로 더럽혀진 우리를 정죄하시는 것이 아니라, 은혜로 덮으시고 정결케 하셔서 새로운 사명자로 세우십니다.\n\n묵상 질문\n1. 나를 정죄하는 사탄의 고소 앞에서 하나님은 어떤 변호자가 되어주시나요?\n2. 내 삶의 ''더러운 옷''은 무엇이며, 하나님께서 입혀주시는 ''아름다운 옷''은 무엇일까요?\n3. 하나님의 용서와 회복을 경험한 후, 내가 감당해야 할 사명은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-27', E'오직 성령의 능력으로 다시 (스가랴 4장)', E'스가랴 4장', E'천사가 스가랴에게 보여준 다섯 번째 환상은 순금 등잔대와 두 감람나무의 환상입니다. 이 환상은 성전 재건이 인간의 힘이 아닌 하나님의 영으로 완성될 것임을 보여주고 있습니다. 스가랴가 본 등잔대는 일곱 등잔과 그것을 연결하는 일곱 관, 그리고 끊임없이 기름을 공급하는 두 감람나무로 구성되어 있었습니다. 이는 하나님의 영이 끊임없이 공급되어 성전이 빛을 발하게 될 것을 상징적으로 보여줍니다.\n\n"이는 힘으로 되지 아니하며 능력으로 되지 아니하고 오직 나의 영으로 되느니라"(슥 4:6)는 말씀은 성전 재건의 핵심 원리를 드러냅니다. 당시 총독 스룹바벨이 직면한 ''큰 산''과 같은 장애물들은 하나님의 영 앞에서 평지가 될 것입니다. 정치적 압력, 경제적 어려움, 백성들의 무관심 등 수많은 난관이 있었지만, 하나님께서는 이 모든 것이 인간의 힘이 아닌 성령의 능력으로 극복될 것임을 약속하십니다.\n\n특별히 주목할 것은 ''작은 일의 날''을 멸시하지 말라는 권면입니다. 16년 전 놓았던 성전 기초 위에 다시 건축을 시작하는 일은 바벨론의 화려했던 성전에 비하면 초라해 보였을 것입니다. 그러나 하나님께서는 스룹바벨의 손에 들린 다림줄을 기뻐하시며, 그 작은 시작이 영광스러운 완성으로 이어질 것을 약속하십니다. 환상의 마지막에 나타나는 ''기름 부음 받은 자 둘''은 대제사장 여호수아와 총독 스룹바벨을 가리키며, 하나님께서는 영적 지도자와 정치적 지도자를 통해 당신의 일을 이루어 가십니다. 이처럼 하나님의 일은 성령의 능력과 신실한 일꾼들을 통해 완성되어 갑니다.', E'오늘의 핵심\n하나님께서는 인간의 힘과 능력이 아닌 오직 성령의 능력으로 당신의 일을 이루시며, 작은 시작을 통해 큰 영광을 드러내십니다.\n\n묵상 질문\n1. 내 삶에서 ''큰 산''처럼 느껴지는 문제들을 나는 무엇으로 해결하려 하고 있나요?\n2. 하나님께서 기뻐하시는 ''작은 일''을 멸시하고 있지는 않나요?\n3. 성령의 기름 부으심을 끊임없이 공급받기 위해 나는 어떻게 살아가야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-02-28', E'오직 성령의 능력으로 다시 (스가랴 5장)', E'스가랴 5장', E'스가랴 선지자에게 주어진 다섯 번째와 여섯 번째 환상은 하나님께서 이스라엘 공동체를 정결케 하시는 과정을 보여줍니다. 날아가는 두루마리 환상은 온 땅에 내리는 저주의 선언으로, 도둑질하는 자와 거짓 맹세하는 자에 대한 심판을 담고 있습니다. 이 두루마리의 크기가 성막의 성소와 같은 치수(20×10규빗)라는 점은 의미심장합니다. 하나님의 거룩한 임재의 장소와 같은 크기의 심판이 온 땅을 덮는다는 것은, 거룩하신 하나님의 기준이 모든 삶의 영역에 적용됨을 보여줍니다.\n\n이어지는 에바 속의 여인 환상은 더욱 극적입니다. 에바는 곡물을 담는 큰 통으로, 경제 활동의 기본 단위를 상징합니다. 그 안에 앉아 있는 여인은 ''악'' 그 자체로 규정됩니다. 천사는 이 악을 에바 속에 가두고 납으로 봉인한 후, 날개 달린 두 여인이 그것을 시날 땅으로 옮겨가게 합니다. 시날은 바벨론 지역으로, 인간의 교만과 우상숭배의 발원지였습니다. 악이 제자리로 돌아가는 이 장면은 하나님께서 당신의 백성 가운데서 악을 완전히 제거하시는 정결 작업을 보여줍니다.\n\n성전 재건 중에 주어진 이 환상들은 단순히 건물을 세우는 것이 아니라 백성의 내면을 정결케 하는 것이 하나님의 관심사임을 드러냅니다. 외형적 종교 활동만으로는 충분하지 않습니다. 일상의 도덕적 삶과 진실한 언행이 하나님께서 원하시는 참된 예배의 기초가 됩니다. 하나님께서는 악을 제거하시되 단순히 파괴하시는 것이 아니라, 그것이 속한 곳으로 돌려보내심으로써 당신의 백성을 거룩한 공동체로 세워가십니다.', E'오늘의 핵심\n하나님께서는 날아가는 두루마리와 에바 속의 여인 환상을 통해 이스라엘 공동체의 도덕적, 영적 정결을 이루시며, 참된 성전은 깨끗한 삶의 터 위에 세워짐을 보여주십니다.\n\n묵상 질문\n1. 내 삶 속에서 하나님께서 제거하기 원하시는 ''도둑질''과 ''거짓 맹세''는 무엇일까요?\n2. 악을 에바에 가두어 시날로 보내시는 하나님의 정결케 하시는 은혜를 경험한 적이 있나요?\n3. 외적인 신앙생활과 내면의 거룩함이 일치하지 않는 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-01', E'오직 성령의 능력으로 다시 (스가랴 6장)', E'스가랴 6장', E'네 병거의 환상을 통해 하나님께서는 온 땅을 다스리시는 주권자이심을 보여주십니다. 각기 다른 색의 말들이 끄는 네 병거는 하늘의 네 바람으로서, 온 세상의 주 앞에 서 있다가 사방으로 나아갑니다. 특별히 북쪽으로 나간 자들이 "북쪽에서 내 영을 쉬게 하였느니라"(슥 6:8)는 선언은 바벨론에 대한 심판이 완성되었음을 알려줍니다. 이는 포로 귀환 공동체에게 과거의 압제자들에 대한 하나님의 심판이 이루어졌다는 확신을 주는 메시지였습니다.\n\n이어지는 대관식 환상은 더욱 놀라운 미래를 보여줍니다. 바벨론에서 돌아온 헬대와 도비야, 여다야가 가져온 은과 금으로 면류관을 만들어 대제사장 여호수아의 머리에 씌우는 상징적 행위가 펼쳐집니다. 이는 단순한 제사장 임직식이 아니라, 메시아 시대에 대한 예언적 행동이었습니다. "싹"이라 불리는 이가 나타나 여호와의 전을 건축하고, 왕과 제사장의 직분을 동시에 수행하며 "이 둘 사이에 평화의 의논이 있으리라"는 약속은 다윗 왕조와 제사장직의 완전한 연합을 예고합니다.\n\n면류관을 성전에 보관하라는 명령은 이 약속이 미래에 성취될 것임을 상기시키는 기념물의 역할을 하게 됩니다. "먼 데 사람들이 와서 여호와의 전을 건축하리니"라는 예언은 이방인들까지 포함하는 하나님 나라의 확장을 보여줍니다. 스가랴는 절망에 빠진 귀환 공동체에게 현재의 작은 시작이 얼마나 위대한 미래로 이어질지를 보여주며, 그들의 순종이 하나님의 원대한 계획 안에서 귀중한 의미를 갖는다는 것을 깨닫게 합니다.', E'오늘의 핵심\n하나님께서는 온 땅을 다스리시는 주권과 함께, 왕이시며 제사장이신 메시아를 통해 완성될 구원의 청사진을 보여주십니다.\n\n묵상 질문\n1. 하나님의 주권이 온 세상에 미친다는 사실이 내게 어떤 위로를 주나요?\n2. 왕과 제사장의 역할을 동시에 감당하실 예수님을 어떻게 기다리고 있나요?\n3. 작은 순종이 하나님의 큰 계획에 쓰임받는다는 약속을 믿고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-02', E'유다 민족의 위기 (에스더 1장)', E'에스더 1장', E'페르시아 제국의 화려한 수산 궁전에서 벌어진 일은 한 나라의 흥망성쇠가 얼마나 인간의 교만과 연약함에 달려 있는지를 보여줍니다. 아하수에로 왕은 즉위 3년째에 무려 180일 동안 잔치를 베풀며 자신의 부와 권력을 과시합니다. 이어서 수산성 백성들을 위해 7일간 더 잔치를 열었는데, 그 호사스러움은 대리석 기둥과 금은 장식, 각기 다른 모양의 금잔에서 드러납니다. 이러한 과시욕은 단순히 부를 자랑하는 데 그치지 않고, 왕후 와스디까지도 전시의 대상으로 삼으려 합니다.\n\n제7일째 되던 날, 술에 취한 왕은 일곱 내시를 보내 왕후 와스디에게 왕관을 쓰고 나와 그녀의 아름다움을 뭇 백성과 관리들 앞에 보이라고 명합니다. 그러나 와스디는 이 명령을 거부합니다. 성경은 그녀가 거부한 이유를 밝히지 않지만, 왕의 요구가 왕후의 품위를 손상시키는 부당한 것이었음을 짐작할 수 있습니다. 와스디의 거부에 격분한 왕은 현자들과 의논한 끝에 그녀를 폐위시키고, 다시는 왕 앞에 나오지 못하게 하는 조서를 내립니다.\n\n이 사건의 본질은 단순한 부부 갈등이 아니라 권력의 오용과 인간 존엄성의 문제입니다. 왕의 측근 므무간은 왕후의 행동이 모든 여인들에게 영향을 미쳐 남편을 멸시하게 될 것이라며, 왕후를 폐위시키고 모든 남편이 집안의 주관자가 되어야 한다는 조서를 반포하도록 건의합니다. 한 사람의 상한 자존심이 제국 전체의 가정 질서를 뒤흔드는 법령으로 이어진 것입니다.\n\n에스더서 1장은 겉으로는 하나님의 이름이 전혀 등장하지 않지만, 인간의 교만과 권력 남용이 어떤 결과를 가져오는지를 보여주며, 동시에 하나님께서 이런 인간의 어리석음조차도 당신의 구원 계획 안에서 사용하실 것을 암시합니다. 와스디의 폐위는 결국 에스더가 왕후가 되는 길을 열었고, 이는 후에 유다 민족을 구원하는 결정적인 계기가 됩니다. 우리의 삶에서도 부당해 보이는 상황과 권력의 횡포를 만날 때, 그 너머에서 일하시는 하나님의 섭리를 신뢰하는 믿음이 필요합니다.', E'오늘의 핵심\n인간의 교만과 권력 남용은 파괴적인 결과를 낳지만, 하나님은 그러한 인간의 어리석음마저도 당신의 구원 계획을 이루시는 도구로 사용하십니다.\n\n묵상 질문\n1. 내 삶에서 권력이나 지위를 남용하여 다른 사람의 존엄성을 해친 적은 없습니까?\n2. 부당한 요구 앞에서 와스디처럼 용기 있게 거부할 수 있는 신앙의 힘이 있습니까?\n3. 불의한 상황 속에서도 하나님의 섭리가 일하고 계심을 믿고 기다릴 수 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-03', E'유다 민족의 위기 (에스더 2장)', E'에스더 2장', E'와스디가 폐위된 후, 페르시아 제국의 왕궁은 새로운 왕후를 찾는 일로 분주해집니다. 왕의 신하들이 제안한 대로 제국 전역에서 아름다운 처녀들이 수산 궁으로 모여듭니다. 이 거대한 선발 과정 속에서 하나님은 조용히 그분의 계획을 진행하고 계셨습니다. 바벨론 포로로 끌려온 베냐민 지파 사람 모르드개가 양육하던 에스더도 왕궁으로 들어가게 됩니다.\n\n에스더는 부모를 잃은 고아였지만, 사촌 오빠인 모르드개의 보살핌 속에서 자랐습니다. 그녀가 왕궁으로 들어갈 때, 모르드개는 중요한 지시를 합니다. 자신의 민족과 종족을 밝히지 말라는 것이었습니다. 이는 단순한 신변 보호를 넘어, 하나님의 백성이 이방 땅에서 살아가는 지혜였습니다. 에스더는 이 말씀에 순종하며, 왕궁에서도 모르드개의 가르침을 변함없이 따릅니다.\n\n궁녀를 주관하는 헤개는 에스더를 특별히 좋게 보았고, 그녀에게 은혜를 베풉니다. 열두 달의 정결 기간을 거쳐 왕 앞에 나아간 에스더는 헤개가 정한 것 외에는 아무것도 더 구하지 않았습니다. 이러한 겸손함과 절제는 모든 사람에게 사랑받는 품성이 되었고, 마침내 아하수에로 왕의 마음도 사로잡게 됩니다. 왕은 에스더를 와스디 대신 왕후로 삼고 성대한 잔치를 베풉니다.\n\n한편 모르드개는 날마다 후궁 뜰 앞을 왕래하며 에스더의 안부를 살폈고, 대궐 문에서 왕을 섬기던 중 왕을 암살하려는 음모를 발견하여 에스더를 통해 왕에게 알립니다. 이 일로 인해 모르드개의 충성은 궁중 일기에 기록됩니다.\n\n에스더가 왕후가 되기까지의 과정은 결코 우연이 아니었습니다. 고아였던 한 소녀가 제국의 왕후가 되는 극적인 신분 상승 뒤에는 하나님의 섭리가 있었습니다. 모르드개의 신실한 양육, 에스더의 순종과 겸손, 그리고 때를 따라 역사하시는 하나님의 손길이 함께했습니다. 우리의 평범한 일상 속에서도 하나님은 당신의 백성을 통해 구원의 역사를 준비하고 계십니다.', E'오늘의 핵심\n하나님께서는 고아 에스더를 페르시아의 왕후로 세우시며, 장차 있을 민족 구원의 도구로 준비시키십니다. 에스더의 순종과 겸손은 하나님의 섭리 안에서 빛을 발합니다.\n\n묵상 질문\n1. 내 삶의 평범한 자리에서도 하나님의 특별한 계획이 있음을 믿고 있습니까?\n2. 에스더처럼 권위자의 지도에 순종하며 겸손히 행하고 있습니까?\n3. 모르드개처럼 맡은 자리에서 충성스럽게 섬기고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-05', E'유다 민족의 위기 (에스더 3장)', E'에스더 3장', E'아하수에로 왕 치하에서 아각 사람 하만이 최고위직에 오르며 페르시아 제국에 어두운 그림자가 드리워지기 시작합니다. 모든 신하가 왕의 명령대로 하만에게 절하는 가운데, 유다인 모르드개만이 무릎을 꿇지도 절하지도 않습니다. 이는 단순한 불복종이 아니라 하나님 외에는 그 누구에게도 경배하지 않겠다는 신앙적 결단이었습니다. 그러나 하만의 분노는 한 개인을 넘어 민족 전체를 향한 살의로 번집니다. "모르드개만 죽이는 것이 부족하다"고 여긴 하만은 페르시아 전역의 유다인을 몰살시킬 음모를 꾸밉니다.\n\n하만의 계략은 치밀했습니다. 그는 왕에게 유다인들이 왕의 법을 지키지 않는 위험한 민족이라고 거짓 고발하며, 은 일만 달란트라는 막대한 뇌물까지 제시합니다. 왕은 깊이 생각해보지도 않고 자신의 인장 반지를 하만에게 넘겨주며 "너의 소견에 좋을 대로 행하라"고 합니다. 이로써 아달월 십삼일, 단 하루 만에 남녀노소를 막론하고 모든 유다인을 학살하라는 끔찍한 조서가 페르시아 전역에 반포됩니다.\n\n본문은 권력의 오만과 증오가 어떻게 무고한 생명들을 위협하는지 생생하게 보여줍니다. 하만의 개인적 자존심이 한 민족의 생존을 위협하는 대학살 계획으로 확대되는 과정은, 악이 얼마나 빠르게 번져나갈 수 있는지를 경고합니다. 동시에 신앙의 원칙을 지키려는 모르드개의 모습은 타협하지 않는 믿음이 때로는 큰 대가를 요구할 수 있음을 보여줍니다.\n\n오늘날에도 우리는 크고 작은 하만들을 마주합니다. 권력을 남용하고, 자신과 다른 이들을 배척하며, 증오를 부추기는 목소리들이 여전히 존재합니다. 그러나 하나님은 역사의 주관자이십니다. 보이지 않는 곳에서도 당신의 백성을 지키시고, 악한 계획을 무너뜨리시는 분이십니다. 모르드개처럼 신앙의 원칙을 지키는 용기와, 다가올 위험 앞에서도 하나님을 신뢰하는 믿음이 우리에게 필요합니다.', E'오늘의 핵심\n한 사람의 교만과 증오가 민족 전체의 생존을 위협하는 대학살 계획으로 번지지만, 하나님은 보이지 않는 곳에서 당신의 백성을 위한 구원을 예비하고 계십니다.\n\n묵상 질문\n1. 신앙의 원칙을 지키기 위해 불이익을 감수한 적이 있으신가요?\n2. 내 주변에서 약자를 향한 편견과 증오의 목소리를 들을 때 어떻게 반응하시나요?\n3. 위기의 순간에도 하나님께서 역사를 주관하신다는 믿음을 갖고 있으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-06', E'유다 민족의 위기 (에스더 4장)', E'에스더 4장', E'페르시아 제국 전역에 유다 민족을 멸절하라는 조서가 내려진 후, 모르드개는 굵은 베 옷을 입고 재를 뒤집어쓴 채 대궐 문 앞에서 대성통곡합니다. 이는 단순한 개인적 슬픔의 표현이 아니라, 민족 전체가 직면한 절체절명의 위기를 하나님 앞에 아뢰는 간절한 호소였습니다. 각 지방의 유다인들도 금식하며 울부짖으며 재에 누워 하나님께 부르짖었습니다.\n\n왕궁 안의 에스더는 처음에는 이 위기의 전모를 알지 못했습니다. 하지만 모르드개를 통해 하만의 음모와 민족 말살 계획을 알게 되자, 그녀 앞에는 생명을 건 선택이 놓입니다. 당시 페르시아 법에 따르면 왕이 부르지 않았는데 왕 앞에 나아가는 것은 죽음을 의미했습니다. 에스더가 왕에게 나아가지 못한 지도 이미 삼십 일이 지난 상황이었습니다.\n\n모르드개는 에스더에게 중요한 메시지를 전합니다. "네가 왕후의 자리를 얻은 것이 이 때를 위함이 아닌지 누가 알겠느냐"(에 4:14). 이 말씀은 우연처럼 보이는 일들 속에도 하나님의 섭리가 있음을 깨닫게 합니다. 에스더가 왕후가 된 것은 단지 개인의 영광을 위해서가 아니라, 바로 이 위기의 순간에 민족을 구원할 도구로 쓰임받기 위함이었습니다.\n\n에스더의 결단은 놀랍습니다. "죽으면 죽으리이다"라는 각오와 함께 그녀는 수산성의 모든 유다인들에게 삼 일간 금식을 요청합니다. 이는 단순히 용기를 내는 것이 아니라, 하나님께 전적으로 의지하며 나아가는 믿음의 결단이었습니다. 왕후의 화려한 지위도, 왕궁의 안전도 그녀가 하나님 앞에서 받은 소명을 회피하는 이유가 될 수 없었습니다.\n\n오늘 우리도 각자의 자리에서 하나님의 부르심을 받고 있습니다. 때로는 위험하고 불편한 선택을 해야 할 때도 있습니다. 그러나 하나님께서는 우리를 지금 이 자리에 ''이 때를 위하여'' 세우셨습니다. 두려움 앞에서도 기도로 나아가며, 하나님의 뜻을 분별하고 순종하는 믿음의 결단이 필요합니다.', E'오늘의 핵심\n민족의 생사가 걸린 위기 앞에서 에스더는 "죽으면 죽으리이다"라는 믿음의 결단으로 금식 기도하며 하나님께서 자신을 왕후로 세우신 목적을 깨닫고 순종합니다.\n\n묵상 질문\n1. 하나님께서 나를 지금 이 자리에 두신 목적은 무엇일까요?\n2. 두려움과 안전 사이에서 믿음의 결단을 미루고 있는 일은 없나요?\n3. 위기의 순간에 먼저 기도와 금식으로 하나님께 나아가고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-07', E'유다 민족의 위기 (에스더 5장)', E'에스더 5장', E'삼일 간의 금식 기도가 끝났습니다. 에스더는 왕후의 예복을 입고 왕궁 안뜰에 섭니다. 왕이 부르지 않았는데 왕 앞에 나아가면 죽을 수도 있는 페르시아의 법 앞에서, 에스더는 생명을 건 발걸음을 내딛습니다. 그런데 놀라운 일이 일어납니다. 왕이 에스더를 보고 금 규를 내민 것입니다. 이는 단순한 호의가 아니라 하나님의 섭리하심이었습니다. 왕은 나라의 절반이라도 주겠다고 말할 정도로 에스더에게 호의를 보입니다.\n\n그러나 에스더는 서두르지 않습니다. 당장이라도 하만의 악한 계획을 고발하고 싶었겠지만, 그녀는 왕과 하만을 잔치에 초대합니다. 첫 번째 잔치에서도 왕이 소원을 물었을 때, 에스더는 다시 한 번 내일의 잔치로 미룹니다. 이는 단순한 망설임이 아니라 지혜로운 기다림이었습니다. 하나님의 때를 분별하며 상황을 신중히 살피는 믿음의 행동이었습니다.\n\n한편 하만은 왕후의 잔치에 초대받은 영광에 도취되어 의기양양해합니다. 그러나 대궐 문에서 여전히 자신에게 절하지 않는 모르드개를 보자 분노가 치밀어 오릅니다. 집에 돌아온 하만은 자신의 부와 영광을 자랑하면서도 "유다 사람 모르드개가 대궐 문에 앉은 것을 보는 동안에는 이 모든 일이 만족하지 아니하도다"라고 말합니다. 그의 아내와 친구들은 오십 규빗 높이의 나무를 세워 모르드개를 매달라고 부추깁니다.\n\n하만의 모습은 교만이 어떻게 사람을 파멸로 이끄는지를 보여줍니다. 가진 것이 아무리 많아도 한 사람의 경배를 받지 못한다는 이유로 모든 것이 무의미하다고 느끼는 그의 마음은 이미 병들어 있었습니다. 반면 에스더는 왕후의 권위를 가지고도 겸손히 하나님의 때를 기다리며 지혜롭게 행동합니다.\n\n우리도 때로는 즉각적인 해결을 원하며 조급해하지만, 하나님께서는 기다림을 통해 더 완전한 구원을 예비하십니다. 에스더의 신중한 기다림과 하만의 성급한 교만이 대조를 이루는 이 장면에서, 우리는 하나님의 때를 분별하며 겸손히 나아가는 지혜를 배우게 됩니다.', E'오늘의 핵심\n에스더는 생명의 위험을 무릅쓰고 왕 앞에 나아갔지만, 성급히 행동하지 않고 하나님의 때를 기다리며 지혜롭게 상황을 이끌어갑니다.\n\n묵상 질문\n1. 급한 상황에서도 하나님의 때를 기다리며 지혜롭게 행동하고 있습니까?\n2. 하만처럼 가진 것에 만족하지 못하고 작은 일에 분노하는 마음은 없습니까?\n3. 에스더처럼 기도 후에도 신중하게 한 걸음씩 나아가는 믿음이 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-08', E'에스라의 결심 (에스라 7장)', E'에스라 7장', E'바벨론 포로에서 1차 귀환이 있은 지 약 80년이 지났습니다. 아닥사스다 왕이 페르시아를 다스리던 때, 하나님께서는 특별한 인물을 예비하고 계셨습니다. 에스라는 대제사장 아론의 16대 손으로서 그 혈통의 정통성을 분명히 하고 있으며, "이스라엘의 하나님 여호와께서 주신 모세의 율법에 익숙한 학자"(스 7:6)로 소개됩니다. 그는 단순히 율법을 아는 것에 그치지 않고, 그것을 연구하여 준행하며 이스라엘에게 가르치기로 결심한 사람이었습니다.\n\n놀라운 것은 이방 왕 아닥사스다가 에스라에게 전폭적인 지원을 아끼지 않았다는 점입니다. 왕은 에스라를 "하늘의 하나님의 율법에 완전한 학자 겸 제사장"으로 인정하며, 예루살렘으로 돌아가고자 하는 모든 이스라엘 백성이 그와 함께 갈 수 있도록 허락합니다. 더 나아가 성전 예배를 위한 막대한 재정 지원과 함께 성전 봉사자들에 대한 세금 면제까지 명령합니다. 이는 단순한 왕의 호의가 아니라 하나님의 주권적인 역사하심이었습니다.\n\n에스라는 바벨론에서 안정되고 영향력 있는 지위를 누리고 있었습니다. 그러나 그는 편안한 삶을 포기하고 험난한 귀환길을 선택합니다. 첫째 달 초하루에 바벨론을 떠나 넉 달이 걸려 다섯째 달 초하루에 예루살렘에 도착한 이 여정은 "하나님의 선한 손의 도우심"으로 가능했습니다. 에스라의 귀환은 성전 재건이라는 외적 과업을 넘어, 하나님의 말씀으로 백성의 영적 갱신을 이루려는 거룩한 사명에서 비롯된 것이었습니다.', E'오늘의 핵심\n하나님께서는 율법에 정통하고 그것을 삶으로 실천하며 가르치기로 결심한 에스라를 통해 포로 귀환 공동체의 영적 개혁을 준비하십니다.\n\n묵상 질문\n1. 에스라처럼 하나님의 말씀을 연구하고 준행하며 가르치는 삶을 살고 있나요?\n2. 편안함과 안정을 포기하고서라도 하나님의 부르심에 순종할 준비가 되어 있나요?\n3. 하나님의 선한 손이 나와 함께하심을 경험하며 살아가고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-09', E'에스라의 결심 (에스라 8장)', E'에스라 8장', E'에스라가 이끄는 2차 포로 귀환은 1차 귀환과는 다른 성격을 지니고 있었습니다. 스룹바벨의 귀환이 성전 재건이라는 물리적 과제를 중심으로 했다면, 에스라의 귀환은 영적 개혁과 율법 교육이라는 내면적 회복을 목표로 삼았습니다. 에스라 8장은 이 귀환 여정의 구체적인 모습을 보여줍니다.\n\n먼저 기록된 것은 귀환자들의 명단입니다. 비느하스, 이다말, 다윗의 후손을 비롯해 열두 가문에서 약 1,500명의 남자들이 에스라와 함께했습니다. 이들은 단순한 이주민이 아니라, 이후 유대 공동체의 영적 재건을 이끌어갈 핵심 인물들이었습니다. 특히 에스라는 아하와 강가에서 레위인이 한 명도 없음을 발견하고, 가시뱌로 사람을 보내어 성전 봉사자들을 데려옵니다. 이는 그가 단순히 귀환만을 목적으로 하지 않고, 예루살렘에서 온전한 예배 공동체를 세우고자 했음을 보여줍니다.\n\n귀환 여정 전, 에스라는 아하와 강가에서 금식을 선포합니다. "우리가 전에 왕에게 아뢰기를 우리 하나님의 손은 자기를 찾는 모든 자에게 선을 베푸시고"(스 8:22)라고 했던 고백 때문에, 그는 왕에게 호위병을 요청하는 대신 오직 하나님의 보호하심만을 의지하기로 결단합니다. 이 금식과 기도는 그들의 여정이 단순한 이주가 아닌 믿음의 순례임을 분명히 보여줍니다.\n\n왕과 백성들이 성전을 위해 바친 막대한 헌물들을 제사장들에게 맡기며, 에스라는 그들이 "여호와께 거룩한 자"임을 상기시킵니다. 넉 달의 긴 여정 끝에 예루살렘에 도착한 그들은 즉시 번제를 드립니다. 이스라엘 전체를 위한 수송아지 열두 마리는 열두 지파의 연합을 상징하며, 포로기를 거치며 흩어졌던 하나님의 백성이 다시 하나 되었음을 선포하는 것이었습니다.', E'오늘의 핵심\n에스라는 귀환 여정을 철저히 기도와 금식으로 준비하며, 오직 하나님의 보호하심만을 의지하여 예루살렘으로 향합니다. 그의 귀환은 단순한 이주가 아닌 영적 회복을 위한 거룩한 부르심이었습니다.\n\n묵상 질문\n1. 에스라가 왕의 호위 대신 하나님의 보호를 택한 것처럼, 나는 어떤 상황에서 하나님만을 의지하는 선택을 하고 있나요?\n2. 귀환자 명단에 이름이 기록된 것처럼, 하나님 나라를 위해 나의 이름이 기억되려면 어떻게 살아야 할까요?\n3. 에스라가 레위인들을 찾아 데려온 것처럼, 공동체의 영적 필요를 채우기 위해 내가 할 수 있는 일은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-10', E'개혁을 위하여', E'에스라 10장', E'에스라가 하나님의 성전 앞에 엎드려 울며 죄를 자복할 때, 놀라운 일이 벌어집니다. 한 사람의 진심 어린 회개가 온 백성의 통곡으로 번진 것입니다. 에스라는 이스라엘이 이방 여인을 아내로 맞이하여 하나님의 명령을 거역하는 현실 앞에서, 남의 죄를 지적하기 전에 먼저 자기 민족의 죄를 자신의 죄로 끌어안고 하나님 앞에 엎드렸습니다. 오랜 포로 생활에서 돌아와 성전까지 재건했음에도 여전히 하나님의 뜻을 떠나 살고 있는 모습이, 그에게는 도저히 외면할 수 없는 아픔이었습니다.\n\n그 진실한 회개 앞에서 백성 가운데 스가냐가 먼저 나서서 말합니다. "이스라엘에게 아직도 소망이 있습니다." 이 고백이 참으로 은혜롭습니다. 죄의 현실을 직시하면서도 절망에 머무르지 않고, 하나님께 돌아가면 여전히 길이 있다고 선언하는 것입니다. 그리고 백성은 실제로 행동에 옮깁니다. 삼 개월에 걸쳐 이방 아내를 떠나보내는 일을 조사하고 정리합니다. 쉬운 결단이 아니었을 것입니다. 이미 자녀를 낳은 가정도 있었습니다. 그럼에도 하나님의 말씀 앞에서 자신의 삶을 바로잡기로 선택한 것입니다.\n\n우리의 일상에도 이미 익숙해져서 돌아볼 생각조차 하지 못하는 영역이 있을 수 있습니다. 직장에서, 관계에서, 습관 속에서 어느새 하나님의 뜻과 멀어진 부분이 없는지 돌아볼 필요가 있습니다. 진정한 개혁은 남을 바꾸는 데서 시작되지 않습니다. 에스라처럼 먼저 자신을 하나님 앞에 내려놓는 데서 시작됩니다. 그리고 스가냐의 고백처럼, 우리에게도 아직 소망이 있습니다. 오늘, 하나님 앞에 내려놓아야 할 것이 무엇인지 조용히 여쭈어 보시기 바랍니다.', E'오늘의 핵심\n민족의 죄를 자신의 것으로 받아들여 회개하는 에스라의 기도를 시작으로 하나님의 언약과 율법에 기반한 개혁의 주춧돌이 놓입니다.\n\n묵상 질문\n1. 하나님은 백성의 죄를 보시고도 왜 자꾸 기회를 주시나요?\n2. 내가 다른 사람의 잘못을 볼 때 에스라처럼 함께 회개할 수 있나요?\n3. 이 시대 내 신앙공동체가 회복되기 위해 내가 먼저 할 것이 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-12', E'최종목표를 위한 중간목표 (느헤미야 1장)', E'느헤미야 1장', E'바벨론 포로에서 돌아온 지 90여 년이 흘렀지만, 예루살렘의 상황은 여전히 참담했습니다. 느헤미야는 페르시아 왕 아닥사스다의 술 관원으로 왕궁에서 안정된 삶을 살고 있었지만, 형제 하나니를 통해 전해들은 예루살렘의 소식은 그의 마음을 무너뜨렸습니다. 성은 허물어지고 성문은 불탔으며, 남은 자들은 큰 환난과 능욕을 당하고 있었습니다.\n\n이 소식을 들은 느헤미야의 반응은 우리에게 깊은 울림을 줍니다. 그는 앉아서 울고 수일 동안 슬퍼하며 금식하고 기도했습니다. 왕궁의 편안함 속에서도 동족의 고통을 자신의 아픔으로 품었던 것입니다. 그의 기도는 단순한 탄식이 아니었습니다. "나와 내 아버지의 집이 범죄하여"(느 1:6)라고 고백하며, 남의 죄가 아닌 자신과 공동체의 죄를 먼저 회개했습니다.\n\n느헤미야의 기도에는 하나님의 언약에 대한 확고한 믿음이 담겨 있습니다. 그는 모세에게 주신 약속, 곧 흩어진 백성이라도 회개하고 돌아오면 다시 모으시겠다는 하나님의 말씀을 붙잡았습니다. 이는 단지 과거의 약속을 기억하는 것이 아니라, 현재의 절망적인 상황 속에서도 하나님의 신실하심을 의지하는 믿음의 고백이었습니다.\n\n술 관원이라는 직책은 왕의 신임을 받는 중요한 자리였습니다. 느헤미야는 이 위치가 우연이 아니라 하나님의 섭리임을 알았기에, "오늘 종이 형통하여 이 사람들 앞에서 은혜를 입게 하옵소서"라고 기도합니다. 그는 자신의 안위를 포기하고 무너진 예루살렘을 위해 일어서기로 결심했습니다. 편안한 자리에서 동족의 아픔에 눈물 흘리며 기도하는 한 사람, 그리고 그 기도가 행동으로 이어질 때 하나님의 역사는 시작됩니다.', E'오늘의 핵심\n느헤미야는 왕궁의 안락함 속에서도 예루살렘의 참상을 듣고 눈물로 금식하며 기도했고, 자신의 위치를 하나님의 백성을 위해 사용하기로 결단했습니다.\n\n묵상 질문\n1. 내 주변의 아픔과 필요에 대해 느헤미야처럼 눈물로 기도한 적이 있나요?\n2. 하나님께서 나를 지금 이 자리에 두신 이유는 무엇일까요?\n3. 회개와 중보기도가 내 삶에서 어떤 변화와 행동으로 이어져야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-13', E'최종목표를 위한 중간목표 (느헤미야 2장)', E'느헤미야 2장', E'느헤미야가 술 관원으로 왕을 섬긴 지 어느덧 4개월이 지났습니다. 그동안 그는 예루살렘의 소식을 듣고 금식하며 기도했지만, 왕 앞에서는 늘 평온한 모습을 유지해야 했습니다. 그런데 이날은 달랐습니다. 왕이 느헤미야의 얼굴에서 수심을 발견한 것입니다. 왕 앞에서 개인적인 감정을 드러내는 것은 목숨을 걸어야 할 일이었기에 느헤미야는 크게 두려워했습니다. \n\n그러나 이 위기의 순간이 오히려 하나님의 기회가 되었습니다. 왕이 "네가 무엇을 원하느냐"고 물었을 때, 느헤미야는 즉시 하늘의 하나님께 묵도했습니다. 4개월간의 기도가 이 짧은 순간의 기도로 이어진 것입니다. 그리고 담대히 예루살렘으로 보내달라고 청했습니다. 놀랍게도 왕은 이를 허락했을 뿐 아니라, 통행 조서와 재목까지 제공했습니다. 느헤미야는 이 모든 일을 "내 하나님의 선한 손이 나를 도우시므로"라고 고백합니다.\n\n예루살렘에 도착한 느헤미야는 즉시 일을 시작하지 않았습니다. 사흘을 기다린 후 밤중에 소수의 사람들과 함께 성벽을 살펴보았습니다. 무너진 성벽과 불탄 성문들을 직접 확인한 후에야 비로소 백성들을 모아 비전을 나누었습니다. "예루살렘 성을 건축하여 다시 수치를 당하지 말자"는 그의 외침에 백성들은 "일어나 건축하자"고 화답했습니다. \n\n산발랏과 도비야 같은 대적들의 조롱이 시작되었지만, 느헤미야는 흔들리지 않았습니다. "하늘의 하나님이 우리를 형통하게 하시리니"라는 확신이 있었기 때문입니다. 기도로 준비하고, 하나님의 때를 기다리며, 지혜롭게 행동하는 느헤미야의 모습은 오늘 우리에게도 하나님의 일을 감당하는 길을 보여줍니다.', E'오늘의 핵심\n느헤미야는 기도로 준비하고 하나님의 때를 기다렸으며, 위기의 순간에도 먼저 하나님께 구하는 신앙으로 하나님의 선한 손의 도우심을 경험했습니다.\n\n묵상 질문\n1. 나는 중요한 결정의 순간에 먼저 하나님께 묵도하고 있나요?\n2. 하나님의 때를 기다리며 기도로 준비하고 있는 일은 무엇인가요?\n3. 대적의 조롱 앞에서도 "하늘의 하나님이 형통하게 하시리라"는 확신을 가지고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-14', E'최종목표를 위한 중간목표 (느헤미야 3장)', E'느헤미야 3장', E'느헤미야 3장은 예루살렘 성벽 재건 공사의 구체적인 모습을 보여줍니다. 대제사장 엘리아십부터 시작하여 금장색과 상인들에 이르기까지, 각계각층의 사람들이 자발적으로 참여하여 성벽을 재건하는 장면이 펼쳐집니다. 이 명단은 단순한 기록이 아니라, 하나님의 역사에 동참한 사람들의 이름을 영원히 기억하시는 하나님의 마음을 담고 있습니다.\n\n성벽 재건의 출발점이 양문인 것은 의미심장합니다. 양문은 성전 제사를 위한 희생 제물들이 들어오는 문으로, 대제사장이 먼저 나서서 이 문을 재건하고 성별한 것은 이 공사가 단순한 토목 공사가 아니라 거룩한 사역임을 보여줍니다. 각 사람은 대부분 자기 집 맞은편 부분을 중수했는데, 이는 자신의 삶의 터전을 지키는 일이 곧 공동체 전체를 지키는 일임을 깨닫게 합니다.\n\n주목할 점은 드고아 사람들의 이야기입니다. 그들의 귀족들은 "주인들의 공사를 분담하지 아니하였으나"(5절), 평민들은 두 부분을 중수했습니다(27절). 지도층이 거부한 일을 평범한 사람들이 더 열심히 감당한 것입니다. 또한 살룸의 딸들도 아버지와 함께 성벽을 중수했는데(12절), 이는 남녀노소 구별 없이 모두가 하나님의 일에 부름받았음을 보여줍니다.\n\n이 장에는 42개 그룹이 등장하며, 제사장, 레위인, 지역 지도자, 금장색, 향품 장사, 상인 등 다양한 직업과 계층의 사람들이 함께 일했습니다. 그들은 각자의 전문성과 은사를 가지고 한 부분씩 책임졌고, 그 부분들이 연결되어 완전한 성벽이 되었습니다. 이것이 바로 하나님의 백성이 하나 되어 일하는 모습입니다. 오늘 우리도 각자의 자리에서 맡은 부분을 신실하게 감당할 때, 하나님의 나라가 든든히 세워져 갑니다.', E'오늘의 핵심\n예루살렘 성벽 재건은 각계각층의 사람들이 자신의 자리에서 한 부분씩 책임지며 협력할 때 이루어진 하나님의 역사였습니다.\n\n묵상 질문\n1. 내가 속한 공동체에서 나는 어떤 ''한 부분''을 맡아 섬기고 있나요?\n2. 드고아 귀족들처럼 하나님의 일에 참여하기를 거부하는 내 모습은 없나요?\n3. 서로 다른 은사와 직업을 가진 사람들이 하나 되어 일할 때 어떤 일이 일어날까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-15', E'초막절을 기념한 신앙사경회 (느헤미야 8장)', E'느헤미야 8장', E'예루살렘 성벽 재건이라는 대역사를 마친 이스라엘 백성들에게 이제 더 중요한 과제가 남아 있었습니다. 무너진 성벽을 다시 세우는 것보다 더 시급한 것은 무너진 신앙을 다시 세우는 일이었습니다. 일곱째 달이 되자 백성들이 자발적으로 수문 앞 광장에 모여 학사 에스라에게 모세의 율법책을 가져오기를 청합니다. 이는 하나님의 말씀을 향한 백성들의 갈급함을 보여주는 놀라운 장면입니다.\n\n새벽부터 정오까지 이어진 말씀 낭독의 현장은 참으로 감동적입니다. 에스라가 특별히 지은 나무 강단에 서서 율법책을 펼 때 모든 백성이 일어섰고, 하나님을 송축할 때는 손을 들고 "아멘, 아멘"으로 화답하며 얼굴을 땅에 대고 경배했습니다. 이 날의 예배는 단순한 낭독이 아니었습니다. 레위인들이 백성들 사이에서 율법을 해석하고 가르쳐 모두가 그 뜻을 깨달을 수 있도록 했습니다.\n\n말씀을 들은 백성들의 반응은 눈물이었습니다. 오랜 포로 생활과 귀환 후의 어려움 속에서 잊고 있었던 하나님의 뜻을 깨달았기 때문입니다. 그러나 느헤미야와 에스라는 이날이 거룩한 날임을 선포하며 슬퍼하지 말고 기뻐하라고 권면합니다. "여호와로 인하여 기뻐하는 것이 너희의 힘이니라"(느 8:10)는 선언은 회개의 눈물을 기쁨의 눈물로 바꾸어 놓았습니다.\n\n이어서 백성들은 율법에 기록된 초막절을 지킵니다. 여호수아 시대 이후로 지켜지지 않았던 이 절기를 온 백성이 함께 지키며 크게 기뻐했습니다. 성벽 재건이 외적 회복이었다면, 말씀을 통한 이 영적 각성은 이스라엘의 진정한 회복의 시작이었습니다. 하나님의 백성다운 정체성을 되찾은 이들은 이제 말씀대로 살아가는 새로운 삶을 시작하게 됩니다.', E'오늘의 핵심\n성벽 재건을 마친 이스라엘 백성들이 스스로 모여 하나님의 말씀을 듣고자 했고, 말씀을 깨달은 백성들은 회개의 눈물을 흘렸다가 여호와로 인한 기쁨을 회복했습니다.\n\n묵상 질문\n1. 백성들이 자발적으로 모여 말씀을 청한 것처럼, 나는 하나님의 말씀을 향한 갈급함을 가지고 있나요?\n2. 말씀을 들을 때 회개의 눈물과 기쁨을 동시에 경험한 적이 있나요?\n3. "여호와로 인하여 기뻐하는 것이 너희의 힘"이라는 말씀이 오늘 나에게 주는 의미는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-16', E'초막절을 기념한 신앙사경회 (느헤미야 9장)', E'느헤미야 9장', E'예루살렘 성벽이 완공된 후, 이스라엘 백성은 스물나흗 날에 다시 모여 금식하며 굵은 베옷을 입고 참회의 자리에 나아갑니다. 에스라의 율법 낭독을 통해 하나님의 뜻을 깨달은 백성들은 이제 그들의 죄와 조상들의 허물을 자복하며 진정한 회개의 시간을 갖습니다. 낮 사분의 일은 하나님의 율법책을 듣고, 또 사분의 일은 죄를 자복하며 여호와께 경배하는 모습은 말씀과 기도가 균형을 이룬 참된 영적 각성의 모습을 보여줍니다.\n\n레위인들이 인도하는 이 회개 기도는 이스라엘 역사 전체를 아우르는 장대한 고백입니다. 천지 창조부터 시작하여 아브라함의 부르심, 출애굽의 구원, 광야에서의 인도하심, 그리고 가나안 정착에 이르기까지 하나님의 신실하신 은혜를 회상합니다. 특히 이 기도에서 반복되는 주제는 하나님의 변함없는 사랑과 이스라엘의 거듭된 배반입니다. "그들과 우리 조상들이 교만하고 목을 굳게 하여 주의 명령을 듣지 아니하고"(16절)라는 고백은 단순히 과거의 잘못을 인정하는 것을 넘어, 현재 그들 자신의 모습까지 포함하는 통렬한 자기반성입니다.\n\n이 기도에서 드러나는 하나님의 성품은 공의로우시면서도 긍휼이 풍성하신 분이라는 것입니다. 백성들이 금송아지를 만들어 하나님을 모독했을 때도, 선지자들을 죽이고 율법을 거역했을 때도, 하나님은 그들을 완전히 버리지 않으셨습니다. 오히려 "주의 크신 긍휼로" 구원자들을 보내시고, "여러 번" 건져내시며, 끊임없이 돌아오도록 경계하셨습니다. 이스라엘의 역사는 곧 하나님의 인내와 사랑의 역사였음을 고백하는 것입니다.\n\n포로에서 돌아온 백성들이 이렇게 긴 역사적 회고를 통해 회개하는 이유는 분명합니다. 그들은 조상들의 실패가 자신들에게도 반복될 수 있음을 깨달았기 때문입니다. 성벽 재건이라는 외적 회복만으로는 충분하지 않습니다. 하나님과의 관계가 바로 서지 않으면, 견고한 성벽도 무너질 수밖에 없음을 역사가 증명했습니다. 그래서 그들은 지금 조상들의 죄와 자신들의 죄를 함께 고백하며, 새로운 출발을 다짐하고 있는 것입니다.', E'오늘의 핵심\n포로 귀환 공동체는 이스라엘 역사 전체를 돌아보며 하나님의 신실하심과 자신들의 거역을 고백하고, 조상들의 실패를 반복하지 않기 위해 철저한 회개의 자리로 나아갑니다.\n\n묵상 질문\n1. 내 삶의 역사 속에서 발견되는 하나님의 인내하심과 나의 거역은 무엇인가요?\n2. 참된 회개는 어떻게 과거의 실패를 현재의 변화로 이어지게 할까요?\n3. 하나님의 공의와 긍휼 사이에서 나는 어떤 은혜를 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-17', E'초막절을 기념한 신앙사경회 (느헤미야 10장)', E'느헤미야 10장', E'포로 귀환 공동체가 하나님의 율법 앞에서 눈물로 회개한 후, 그들의 신앙은 구체적인 결단과 실천으로 이어집니다. 느헤미야 10장은 언약 갱신 문서에 인봉하는 지도자들의 명단으로 시작됩니다. 총독 느헤미야를 필두로 제사장들, 레위인들, 그리고 백성의 지도자들이 차례로 이름을 올립니다. 이 명단은 단순한 서명자 목록이 아니라, 하나님 앞에서 새로운 삶을 살겠다는 공동체 전체의 엄숙한 서약을 보여줍니다.\n\n언약의 내용은 매우 구체적이고 실제적입니다. 첫째로 이방인과의 통혼 금지를 명시합니다. 이는 단순한 민족적 순수성 보존이 아니라 신앙의 순전함을 지키려는 의지의 표현입니다. 둘째로 안식일과 안식년 준수를 약속합니다. 안식일에는 매매를 하지 않고, 일곱째 해에는 땅을 쉬게 하며 모든 빚을 탕감하겠다는 것입니다. 이는 하나님께서 창조 질서 속에 심어두신 안식의 리듬을 회복하겠다는 결단입니다.\n\n셋째로 성전 유지를 위한 재정적 책임을 자발적으로 받아들입니다. 매년 성전세를 바치고, 제비를 뽑아 정기적으로 제단에 사를 나무를 공급하며, 각종 첫 열매와 십일조를 충실히 드리기로 합니다. "우리가 우리 하나님의 전을 버려 두지 아니하리라"(느 10:39)는 마지막 선언은 과거 성전을 소홀히 여겼던 실패를 반복하지 않겠다는 강한 의지를 담고 있습니다.\n\n이 언약 갱신은 율법의 무거운 짐을 다시 지는 것이 아니라, 하나님의 은혜에 감사하며 자발적으로 선택한 헌신입니다. 그들은 율법 준수를 통해 하나님과의 관계를 회복하고, 거룩한 공동체로 세워지기를 소망했습니다. 진정한 신앙 개혁은 감정적 회개에 그치지 않고 삶의 구체적인 변화로 나타나야 함을 이 본문은 가르쳐 줍니다.', E'오늘의 핵심\n포로 귀환 공동체는 율법 낭독과 회개 이후, 구체적인 언약 조항들을 정하고 지도자들부터 솔선수범하여 인봉함으로써 하나님께 대한 헌신을 새롭게 다집니다.\n\n묵상 질문\n1. 나의 신앙생활에서 구체적으로 개선하고 싶은 영역은 무엇인가요?\n2. 하나님의 전을 버려두지 않겠다는 결단이 오늘날 우리에게는 어떤 의미일까요?\n3. 신앙 공동체의 일원으로서 내가 감당해야 할 책임은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-19', E'천오백 년 사랑의 아쉬움 (말라기 1장)', E'말라기 1장', E'포로에서 돌아온 이스라엘은 더 이상 우상을 섬기지 않았습니다. 성전도 재건했고, 제사도 드렸습니다. 그런데 하나님께서는 이들에게 먼저 사랑을 고백하십니다. "내가 너희를 사랑하였노라." 아브라함을 부르신 때부터 지금까지, 출애굽과 광야, 가나안 정착과 포로 귀환까지 변함없이 사랑해 오신 분의 고백이었습니다. \n\n그런데 백성의 반응이 충격적입니다. "주께서 어떻게 우리를 사랑하셨나이까?" 이 질문 속에는 하나님의 사랑을 의심하는 냉소가 담겨 있었습니다. 하나님께서는 야곱을 택하시고 에돔을 심판하신 역사를 통해 당신의 사랑을 증명하셨지만, 이스라엘은 여전히 무감각했습니다.\n\n더 심각한 것은 제사장들의 타락이었습니다. 그들은 하나님을 아버지요 주인으로 부르면서도 정작 그분을 공경하지 않았습니다. 제단에는 눈먼 짐승, 저는 짐승, 병든 짐승이 올라갔습니다. 총독에게도 감히 드릴 수 없는 것들을 하나님께 드리면서도 "우리가 어떻게 주를 더럽게 하였나이까"라고 되묻는 뻔뻔함까지 보였습니다.\n\n하나님께서는 차라리 성전 문을 닫을 사람이 있기를 바라실 정도로 탄식하십니다. 형식적인 예배, 마지못해 드리는 제물, 번거로워하며 코웃음치는 태도가 하나님의 마음을 아프게 했습니다. 그럼에도 하나님은 놀라운 약속을 주십니다. "해 뜨는 곳에서부터 해 지는 곳까지의 이방 민족 중에서 내 이름이 크게 될 것이라." 이스라엘이 거부한 그 사랑을 온 세상이 받아들이게 될 것이라는 예언이었습니다.\n\n오늘 우리의 예배는 어떠한지 돌아보게 됩니다. 최선이 아닌 남은 것으로 드리는 예배, 의무감으로 채우는 시간이 되어버리진 않았는지 말입니다. 하나님의 변함없는 사랑 앞에 우리가 드릴 수 있는 것은 온전한 마음과 정성된 예배입니다.', E'오늘의 핵심\n하나님의 변함없는 사랑 고백에 이스라엘은 냉소로 응답했고, 제사장들은 형식적이고 경멸적인 예배로 하나님의 이름을 더럽혔습니다.\n\n묵상 질문\n1. 하나님의 사랑이 당연하게 느껴져서 감사를 잃어버린 적은 없나요?\n2. 내가 하나님께 드리는 예배와 헌신은 최선의 것인가요, 남은 것인가요?\n3. 형식적인 신앙생활에서 벗어나 진정한 예배자가 되려면 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-20', E'천오백 년 사랑의 아쉬움 (말라기 2장)', E'말라기 2장', E'말라기 2장은 무너진 제사장직과 깨어진 언약의 민낯을 적나라하게 드러냅니다. 하나님께서는 특별히 제사장들을 향해 엄중한 경고의 메시지를 전하십니다. 그들은 백성과 하나님 사이의 중보자로 부름받았지만, 오히려 많은 사람을 율법에서 떠나게 만드는 걸림돌이 되어버렸습니다.\n\n하나님께서 레위 지파와 맺으신 언약은 "생명과 평강의 언약"이었습니다. 이 언약을 받은 초기의 레위인들은 하나님을 경외하며 진리의 법을 가르쳤고, 화평과 정직함으로 하나님과 동행하며 많은 사람을 죄악에서 돌이키게 했습니다. 제사장의 입술은 지식을 지켜야 하고, 백성들은 그들에게서 율법을 구해야 한다고 말씀하십니다. 제사장은 만군의 여호와의 사자이기 때문입니다.\n\n그러나 당시의 제사장들은 이 거룩한 부르심을 저버렸습니다. 그들은 옳은 길에서 떠났고, 율법을 행할 때 사람을 차별하며 편파적으로 대했습니다. 그 결과 하나님께서는 그들이 모든 백성 앞에서 멸시와 천대를 당하게 하셨다고 선언하십니다.\n\n제사장들의 타락은 백성 전체의 영적 타락으로 이어졌습니다. 유다 백성은 이방 신을 섬기는 여인들과 결혼하여 하나님의 성결을 욕되게 했고, 어려서 맺은 아내와의 언약을 파기하는 이혼이 만연했습니다. 하나님께서는 "나는 이혼하는 것과 옷으로 학대를 가리는 자를 미워하노라"고 분명히 말씀하십니다. 결혼 언약의 파괴는 단순한 개인의 문제가 아니라 하나님과 맺은 언약에 대한 불신실함을 보여주는 것이었습니다.\n\n가장 충격적인 것은 백성들의 영적 무감각입니다. 그들은 "모든 악을 행하는 자는 여호와의 눈에 좋게 보이며 그에게 기쁨이 된다"고 말하며, "정의의 하나님이 어디 계시냐"고 냉소적으로 묻습니다. 하나님의 공의를 의심하고 그분의 말씀을 괴롭게 하면서도 자신들의 잘못을 깨닫지 못했습니다.\n\n이 말씀은 오늘 우리에게도 깊은 성찰을 요구합니다. 영적 지도자들은 자신의 부르심을 진실하게 감당하고 있는지, 신앙 공동체는 하나님과의 언약을 신실하게 지키고 있는지, 그리고 우리의 신앙이 형식적이고 냉소적으로 변질되지는 않았는지 돌아보게 합니다.', E'오늘의 핵심\n하나님께서는 무너진 제사장직과 깨어진 언약 관계를 통해 이스라엘의 영적 타락을 고발하시며, 참된 회복은 하나님과의 언약에 신실함으로 돌아가는 것임을 보여주십니다.\n\n묵상 질문\n1. 내가 받은 영적 책임과 부르심을 신실하게 감당하고 있는지 점검해 보셨나요?\n2. 하나님과의 언약, 사람과의 약속을 가볍게 여기거나 파기한 적은 없었나요?\n3. 신앙생활이 형식적이 되어 하나님의 공의와 사랑을 의심하게 된 순간은 언제였나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-21', E'천오백 년 사랑의 아쉬움 (말라기 3장)', E'말라기 3장', E'말라기 3장은 하나님의 변하지 않는 성품과 백성의 변덕스러운 마음 사이의 긴장을 보여주고 있습니다. 포로 귀환 후 백성들은 형식적인 예배는 드렸지만, 마음은 하나님께로부터 멀어져 있었습니다. 그들은 십일조와 봉헌물을 아끼며 하나님의 것을 도둑질하고도 "우리가 어떻게 주의 것을 도둑질하였나이까"라고 반문합니다. 더 나아가 "하나님을 섬기는 것이 헛되다"는 냉소적인 말까지 서슴지 않습니다.\n\n이런 백성들에게 하나님은 언약의 사자를 보내실 것을 약속하십니다. 그러나 그 날은 단순한 구원의 날만이 아닙니다. "그는 금을 연단하는 자의 불과 표백하는 자의 잿물과 같을 것"이라는 말씀처럼, 정결케 하시는 심판의 과정을 포함하고 있습니다. 특히 레위 자손들, 즉 하나님을 섬기는 자들부터 먼저 연단하실 것을 말씀하십니다. 이는 하나님께서 당신의 백성을 포기하지 않으시고 끝까지 정결케 하시려는 사랑의 표현입니다.\n\n놀라운 것은 이 모든 불신앙과 배반에도 불구하고 하나님께서 "나 여호와는 변하지 아니하나니"라고 선언하시는 것입니다. 바로 이 변치 않는 성품 때문에 "야곱의 자손들아 너희가 소멸되지 아니하느니라"고 말씀하십니다. 백성의 신실하지 못함이 하나님의 신실하심을 바꿀 수 없었던 것입니다.\n\n그러면서도 하나님은 구체적인 회복의 길을 제시하십니다. "너희의 온전한 십일조를 창고에 들여 나의 집에 양식이 있게 하고 그것으로 나를 시험하여 내가 하늘 문을 열고 너희에게 복을 쌓을 곳이 없도록 붓지 아니하나 보라"는 도전은 형식적 종교가 아닌 실제적 헌신을 요구하시는 것입니다. 십일조는 단순한 물질의 문제가 아니라 하나님을 향한 신뢰와 순종의 표현이었습니다.\n\n말라기는 냉랭해진 신앙 공동체 가운데서도 "여호와를 경외하는 자들"이 있었음을 기록합니다. 그들은 서로 대화하며 신앙을 지켜갔고, 하나님은 그들을 위해 "기념책"에 기록하셨습니다. 이들은 하나님의 "특별한 소유"가 될 것이며, 아들을 아끼듯 아낌을 받을 것입니다. 어두운 시대에도 신실함을 지키는 남은 자들을 통해 하나님의 구원 역사가 이어지는 것을 봅니다.', E'오늘의 핵심\n하나님은 백성의 냉소적 불신앙에도 불구하고 변치 않는 사랑으로 그들을 연단하시며, 진실한 헌신으로 돌아오기를 기다리십니다.\n\n묵상 질문\n1. 나도 모르게 하나님의 것을 도둑질하며 살고 있는 영역은 무엇일까요?\n2. "하나님을 섬기는 것이 헛되다"는 생각이 들 때, 나는 어떻게 신앙을 지켜가고 있나요?\n3. 하나님의 변치 않는 성품이 오늘 나에게 주는 위로와 도전은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-03-22', E'천오백 년 사랑의 아쉬움 (말라기 4장)', E'말라기 4장', E'말라기의 마지막 장은 구약 성경 전체의 마침표이자 새로운 시작을 예고하는 장엄한 선언입니다. 하나님께서는 심판과 구원의 두 얼굴을 동시에 보여주십니다. "용광로 불 같은 날"이 이를 것이며, 그날에 교만한 자와 악을 행하는 자는 지푸라기처럼 타버릴 것이라고 경고하십니다. 뿌리와 가지까지 남김없이 사라질 것이라는 표현은 심판의 철저함을 보여줍니다.\n\n그러나 같은 날이 하나님을 경외하는 자들에게는 전혀 다른 의미로 다가옵니다. "공의로운 해가 떠올라서 치료하는 광선을 비추리니"라는 약속은 심판의 불이 구원의 빛으로 변화됨을 보여줍니다. 외양간에서 막 풀려난 송아지가 기쁨에 뛰는 것처럼, 구원받은 백성이 누릴 자유와 기쁨을 생생하게 그려냅니다. 이는 단순한 구원을 넘어 완전한 회복과 치유의 약속입니다.\n\n하나님께서는 이 약속과 함께 두 가지 중요한 말씀을 더하십니다. 먼저 호렙산에서 모세에게 주신 율법을 기억하라고 하십니다. 이는 하나님의 백성이 걸어야 할 길이 이미 분명히 제시되어 있음을 상기시킵니다. 그리고 엘리야를 보내겠다는 약속으로 구약을 마무리하십니다. 아버지와 자녀의 마음이 서로에게로 돌아오는 화해의 역사가 일어날 것입니다.\n\n이 마지막 장은 400년의 침묵기를 앞두고 주어진 약속이었습니다. 그리고 이 약속은 광야에서 외치는 세례 요한의 음성으로, 궁극적으로는 예수 그리스도의 오심으로 성취됩니다. 심판의 불꽃 같았던 하나님의 공의가 십자가에서 사랑의 불꽃으로 타올랐고, 치료하는 광선은 부활의 새벽빛으로 온 세상을 비추게 되었습니다.\n\n오늘도 우리는 이 두 가지 실재 사이에 서 있습니다. 하나님의 공의로운 심판이 엄연히 존재하지만, 그리스도 안에서 치료와 회복의 빛이 우리를 비추고 있습니다. 그러므로 우리는 하나님을 경외하며 그분의 말씀을 기억하고, 화해의 사역자로 부르심을 받았음을 잊지 말아야 합니다.', E'오늘의 핵심\n구약의 마지막 장은 심판과 구원의 날을 예고하며, 오실 메시아를 통한 완전한 회복을 약속합니다.\n\n묵상 질문\n1. 동일한 하나님의 날이 어떤 이에게는 심판이, 어떤 이에게는 구원이 되는 이유는 무엇일까요?\n2. 하나님을 경외한다는 것이 내 일상에서 구체적으로 어떻게 나타나고 있나요?\n3. 아버지와 자녀의 마음이 돌이켜져야 할 관계가 내 주변에 있다면 어떻게 화해의 다리가 될 수 있을까요?');
